INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony)
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Abu Moh. Rasyid Ridho S.Pd.', '/assets/images/trainers/trainer_3.jpg', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Lembata yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Abu Moh. Rasyid Ridho S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Abu Moh. Rasyid Ridho S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Lembata', 'Nusa Tenggara Timur', 150000000.0, 0.0, 0, '1234', 'Cinta pada pandangan pertama, itulah yang saya rasakan setelah mengikuti pelatihan Metode GASING di Lembata. Selama pelatihan, saya tak hanya belajar, tetapi juga menemukan cara baru dalam mengajar matematika. Kini, GASING, yang berarti Gampang, Asyik, dan Menyenangkan, telah menjadi teman setia saya dan anak- anak didik saya. Metode ini tidak hanya mempermudah pemahaman matematika, tetapi juga membawa semangat baru dalam pengajaran saya. Pelatihan ini memunculkan banyak ide segar, baik dalam permainan matematika berbasis GASING maupun pendekatan kreatif kepada anak-anak. Saya menyadari bahwa matematika bisa menjadi kegiatan yang interaktif dan menyenangkan, bukan lagi pelajaran yang menakutkan. Suasana pelatihan masih sangat melekat, dan saya merasa beruntung bisa menjadi bagian dari program ini, yang telah mengubah cara pandang saya dalam mengajar. Salah satu momen paling berkesan adalah ketika permainan matematika GASING yang saya ciptakan diapresiasi oleh Prof. Yohanes Surya dan diminta untuk digunakan dalam pembelajaran lanjutan. Ini adalah pengakuan yang sangat membanggakan, dan saya menyadari bahwa semua ide kreatif ini lahir berkat GASING dan dukungan dari Prof. Yohanes. Saya sangat bersyukur atas kesempatan yang diberikan oleh metode ini. Setiap hari, saya melihat anak-anak menjadi lebih antusias dalam belajar matematika. Mereka tidak lagi merasa takut, melainkan menikmati proses pembelajaran dengan penuh kegembiraan. Sebagai pendidik, melihat semangat belajar anak- anak adalah kebahagiaan terbesar. Melalui tulisan ini, saya ingin menyampaikan rasa terima kasih yang mendalam kepada GASING dan Prof. Yohanes Surya. Metode ini telah mengubah saya dan memberikan dampak besar pada dunia pendidikan, khususnya dalam pembelajaran matematika. Saya berharap GASING bisa terus berkembang, menginspirasi lebih');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Albertus Angga Utama S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bandar Lampung yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Albertus Angga Utama S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Albertus Angga Utama S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bandar Lampung', 'Lampung', 150000000.0, 0.0, 0, '1234', 'Sebelum mengenal Metode GASING, matematika bagi saya adalah rumus-rumus mati yang harus dihafal anak-anak. Namun, setelah dilatih langsung oleh Prof. Yohanes Surya, saya menyadari pentingnya menanamkan konsep secara konkret dan kritis. Saya melihat anak-anak Lampung yang tadinya takut matematika kini tertawa gembira saat belajar perkalian dan penjumlahan cepat. GASING tidak hanya mengubah cara saya mengajar, tetapi mengembalikan panggilan jiwa saya sebagai pendidik sejati.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Ana Kaprianie S.Pd.', '/assets/images/trainers/trainer_5.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Gunung Mas yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Ana Kaprianie S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Ana Kaprianie S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Gunung Mas', 'Kalimantan Tengah', 150000000.0, 0.0, 0, '1234', 'Awalnya, menjadi seorang guru bukanlah mimpi saya, melainkan hanya sebuah profesi yang menjanjikan karena peluang bekerja masih cukup besar. Saya hanya seorang guru biasa, mengajar dengan kaku dan penuh aturan. Namun, setelah mengikuti Pelatihan GASING, saya menemukan jati diri, harapan, serta mimpi yang membuat saya jauh lebih berarti. Saat ini, saya sangat bersemangat menjalani pekerjaan saya sebagai seorang guru. Saya bukan lagi guru yang mengajar dengan banyak aturan dan kalimat-kalimat sulit yang selalu berpatokan pada buku, terutama dalam pelajaran matematika. Dengan bahasa yang sederhana dan mudah dipahami, serta metode yang asyik, gampang, dan menyenangkan, peserta didik lebih mudah memahami materi matematika yang saya ajarkan. Saya menggunakan berbagai lagu dan permainan menarik, sehingga peserta didik belajar dengan riang hati tanpa rasa takut dalam belajar matematika. Mengajar dengan hati, penuh kesabaran, dan lebih peduli membuat saya menjadi kreatif. Saya suka bernyanyi dan menari, serta selalu ingin melatih logika peserta didik untuk menemukan pola dalam menyelesaikan soal-soal, menjadikan kelas penuh tawa dan keceriaan. Hal ini menjadikan saya guru yang diharapkan oleh peserta didik di sekolah. Mereka akan tersenyum, melambaikan tangan, dan memanggil saya "Ibu Ana" baik di sekolah, di jalan, di pasar, atau di manapun saya berada. Saya merasa begitu diharapkan, begitu berarti, dan berguna bagi orang lain. Saya adalah orang yang tidak pernah berpikir atau bermimpi dapat mengunjungi beberapa daerah di luar Pulau Kalimantan. Namun, dengan GASING, saya diberikan kepercayaan untuk menginspirasi di beberapa daerah di Indonesia. Pengalaman tersebut sangat membuka pandangan dan wawasan saya tentang beragam karakteristik dan adat di berbagai daerah. Dari pengalaman ini, saya menemukan banyak solusi untuk masalah dan kekurangan dalam mengajar, sehingga dapat membuat saya lebih baik ke depan.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Andika Monalisa S.Pd., S.Si.', '/assets/images/trainers/trainer_6.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Banyuwangi yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Andika Monalisa S.Pd., S.Si. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Andika Monalisa S.Pd., S.Si. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Banyuwangi', 'Jawa Timur', 150000000.0, 0.0, 0, '1234', 'KARENA SEMUA DARI AKAN SAMPAI KE TRAINER ANDIKA MONALISA ASAL SD NEGERI 3 SARONGAN, KAB. BANYUWANGI, JAWA TIMUR G A S I N G D I H A T I K U / 6 hati hati');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Aprina Saima Putri S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Tapanuli Tengah yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Aprina Saima Putri S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Aprina Saima Putri S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Tapanuli Tengah', 'Sumatera Utara', 150000000.0, 0.0, 0, '1234', 'Pelatihan Metode GASING di Tapanuli Tengah telah membuka mata saya bahwa tidak ada anak yang bodoh. Melalui proses belajar yang gampang, asyik, dan menyenangkan, saya melihat perubahan luar biasa pada anak-anak yang sebelumnya dinilai lambat belajar. Mereka kini penuh percaya diri dan mampu mencongak cepat. GASING mengajarkan saya untuk mengajar dengan hati dan ketulusan, menyebarkan kegembiraan belajar numerasi di pelosok Sumatera.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Arlini M. Situmorang S.Pd.', '/assets/images/trainers/trainer_8.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Dairi yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Arlini M. Situmorang S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Arlini M. Situmorang S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Dairi', 'Sumatera Utara', 150000000.0, 0.0, 0, '1234', 'SELAMAT ULANG TAHUN, PROF Selamat ulang tahun, Prof. Saya berdoa semoga prof panjang umur, sehat selalu dan bahagia selalu. Sebelumnya saya mau berterima kasih sekali kepada Bapak Prof, karena berkat gasing saya bisa lebih banyak belajar dan saya memiliki relasi yang luas. Jujur, saya dulu orangnya introvert dan sangat tidak suka bertemu dengan orang baru, namun setelah saya bertemu dengan gasing saya perlahan sudah berubah, saya senang bertemu org baru dan teman baru. Terima kasih sudah lahir di dunia prof, terima kasih sudah menciptakan metode yang luar biasa. Panjang umur ya, Prof dan tetap menjadi berkat buat banyak orang ❤ TRAINER');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Arnacikalati S.Pd.SD', '/assets/images/trainers/trainer_9.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bangka Tengah yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Arnacikalati S.Pd.SD dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Arnacikalati S.Pd.SD membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bangka Tengah', 'Kepulauan Bangka Belitung', 150000000.0, 0.0, 0, '1234', 'Saya biasa dipanggil Ibu Cika. Pada tahun 2005, saya menjadi seorang guru, sedangkan hobi saya adalah bernyanyi dan menari. Saya berpikir, apa yang bisa saya berikan kepada murid-murid saya dengan hobi tersebut, sehingga pembelajaran yang saya berikan dapat berkembang? Selama 10 tahun, saya mendidik murid-murid saya dengan cara yang membosankan, terutama dalam pelajaran matematika, yang bagi saya terasa membosankan, menakutkan, menyebalkan, dan menjengkelkan. Saya sempat berpikir, apa yang akan terjadi pada murid-murid jika metode yang saya ajarkan terasa membosankan. Pada bulan Oktober 2023, saya diminta untuk mengikuti pelatihan GASING karena tidak ada guru lain yang mau. Saya berpikir, "Apa sih GASING? Matematika lagi, pasti membosankan." Dengan berat hati, saya terpaksa mengikuti pelatihan tersebut. Pada hari pertama, saya merasa mendapatkan materi yang diajarkan di kelas rendah, padahal saya mengajar di kelas tinggi. Dengan percaya diri, saya memberikan tanggapan negatif kepada trainer. Namun, seiring berjalannya waktu, saya mulai menyadari pentingnya diajarkan dari dasar matematika dan konsep pola dalam Metode GASING. Trainer yang luar biasa dan selalu sabar memberikan ilmu membuat saya mengikuti pelatihan dengan bahagia, dan hobi saya dalam bernyanyi dan menari dapat tersalurkan. Pelatihan pun selesai, dan saya kembali ke sekolah. Saya sudah tidak sabar ingin membagikan Metode GASING kepada murid-murid dan rekan guru di sekolah. Saya diberi kesempatan untuk berbagi ilmu dengan murid dan guru-guru di luar daerah. GASINGluar biasa! Metode ini bisa membuat murid dan guru bahagia belajar. Saya bahkan bisa pergi ke daerah lain dengan pesawat, mengenal budaya baru, dan berkolaborasi dengan para guru di seluruh Indonesia. Terima kasih kepada Guru Hebat Prof. Yohanes Surya dan Tim GASING yang telah menjadikan saya Trainer Nasional. Karena GASING, derajat dan martabat saya bisa dipandang orang lain. Saya juga memperoleh ilmu dan metode yang baik, tidak hanya untuk');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Asrida Sigiro M.Pd.', '/assets/images/trainers/trainer_10.jpg', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Simalungun yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Asrida Sigiro M.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Asrida Sigiro M.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Simalungun', 'Sumatera Utara', 150000000.0, 0.0, 0, '1234', 'Saya, Asrida Sigiro, adalah seorang guru yang dulunya ditakuti oleh siswa. Wajah saya yang penuh amarah, tangan yang sering terangkat, dan kata-kata yang tajam membuat setiap hari di kelas terasa seperti medan pertempuran, bukan hanya bagi murid- murid saya, tetapi juga bagi diri saya sendiri. Saya mengajar dengan kemarahan, berpikir bahwa ketegasan berlebihan adalah jalan terbaik untuk mendisiplinkan. Murid-murid tidak melihat saya sebagai sosok yang mereka percayai; saya adalah bayangan yang mereka hindari. Saya tidak bangga dengan masa itu, tetapi begitulah saya dulu sebelum hidup saya berubah sepenuhnya. Perubahan itu datang saat saya bertemu Profesor Yohanes Surya dan Metode GASING yang luar biasa. GASING bukan sekadar cara mengajar matematika, tetapi sebuah pintu menuju pandangan baru. Di situlah perjalanan perubahan saya dimulai perjalanan yang tidak hanya mengubah cara saya mengajar, tetapi juga cara saya hidup. Gampang, Asyik, dan Menyenangkan itulah yang dibawa GASING. Awalnya, saya menerapkannya hanya dalam metode mengajar, tetapi seiring waktu, nilai-nilainya masuk ke dalam hati dan jiwa saya. Saya tidak lagi menjadi guru yang suka marah-marah. Tangan saya yang dulu sering terangkat untuk menghukum, kini terulur dengan penuh kasih sayang. Kata-kata yang dulu keluar dengan kemarahan, sekarang digantikan oleh senyum dan dorongan semangat. GASING mengajarkan saya bahwa mengajar bukan sekadar soal ketegasan, melainkan tentang memberi diri sepenuh hati demi mencapai misi mulia. Setiap anak adalah permata yang menunggu diasah dengan cinta dan kepercayaan. Kini, tatapan takut yang dulu saya lemparkan kepada murid-murid telah berubah menjadi pandangan hangat, penuh cinta, dan kasih. Bersama GASING, saya telah menjelajahi Indonesia, dari Sabang hingga Merauke, menembus batas kota besar hingga desa-desa terpencil yang belum tersentuh oleh ilmu. Kami mengemban misi mulia misi menjadikan Indonesia pandai berhitung.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Atty Marta Kambu S.Pd.', '/assets/images/trainers/trainer_11.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Maybrat yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Atty Marta Kambu S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Atty Marta Kambu S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Maybrat', 'Papua Barat', 150000000.0, 0.0, 0, '1234', 'Saya adalah seorang guru di daerah pinggiran, tepatnya di Kabupaten Maybrat, Provinsi Papua Barat Daya. Awalnya, saya merupakan seorang guru yang judes, dengan metode pengajaran yang jauh dari suasana menyenangkan, dan kelas yang tidak aktif. Pada bulan April 2023, pelatihan pembelajaran Matematika dengan Metode GASING sampai di Maybrat. Sungguh luar biasa Bapak Profesor Yohanes Surya yang telah berkorban demi pendidikan, bahkan rela menempuh perjalanan yang sangat jauh hingga tiba di Kabupaten Maybrat. Saya mengikuti pelatihan tersebut dengan sangat antusias, dan kini saya telah berubah menjadi guru yang lebih aktif, memiliki banyak ide dalam pembelajaran, serta mampu memadukan kegiatan belajar sambil bermain. Hal ini menciptakan suasana belajar yang sangat menyenangkan, bahkan siswa dari kelas lain ingin bergabung untuk belajar bersama saya. Terkadang saya merasa kurang enak terhadap teman sejawat, karena siswa-siswi di kelas mereka lebih memilih belajar bersama saya. Karena GASING, kini saya memiliki hati yang mau melayani dan berbagi tanpa memandang latar belakang apapun. Rasa cinta terhadap tanah air sungguh besar, sehingga saya bersedia pergi ke pelosok Indonesia, bahkan daerah konflik sekalipun, demi kemajuan negara Indonesia tercinta ini. Beberapa waktu lalu, sebelum saya pergi ke Kabupaten Paniai untuk melakukan pengimbasan Pembelajaran Matematika dengan Metode GASING, saya berpamitan dan memberikan nasihat kepada para murid di kelas. Saya mendapatkan pernyataan yang membuat saya terharu, yaitu: "Kami suka ke sekolah karena ada Ibu Atty. Ibu guru pergi lama atau cepat, kami tetap ingin diajar sama Bu Guru. Hal yang bikin kami sedih adalah ketika ibu guru harus berangkat pengimbasan," ucap salah satu murid bernama Ledy Bontong sambil menangis. Dalam hati, saya sangat terharu karena kini saya sangat dicintai oleh siswa-siswi saya di sekolah. Setelah pulang dari pengimbasan');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Bambang Cahyono S.Pd.', '/assets/images/trainers/trainer_12.jpg', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Lampung Barat yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Bambang Cahyono S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Bambang Cahyono S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Lampung Barat', 'Lampung', 150000000.0, 0.0, 0, '1234', 'Berawal dari pelatihan Metode GASING di Kabupaten Lampung Barat, saya mengenal metode baru yang disebut GASING (Gampang, Asyik, dan Menyenangkan). Terima kasih kepada Prof. Yohanes Surya, Ph.D., dan Gasing Academy yang telah memberi saya kesempatan untuk menjadi trainer nasional. Dengan GASING, kami bisa mengenal, mengajar, bahkan dicintai oleh siswa dan guru-guru di seluruh Indonesia. Kami mengajar dengan hati dan cinta, karena dalam GASING kami selalu menerapkan 8C (Critical Thinking, Communication, Collaboration, Creativity, Culture, Character, Computational Logic, dan Compassion). Ini membuat cara mengajar saya di sekolah menjadi lebih kreatif dan menyenangkan, bahkan menjadikan pelajaran sebagai sesuatu yang dinantikan oleh siswa. Matematika kini tak lagi sulit, tidak lagi membosankan, karena GASING telah mengubahnya dari pelajaran yang ditakuti menjadi pelajaran yang disukai dan dicintai. Di setiap pengimbasan, saya menemukan keluarga baru dari seluruh Indonesia. Pengalaman berharga saya dapatkan melalui GASING, terlebih lagi saat saya bisa menginjakkan kaki di Tanah Papua, di mana saya yang berasal dari provinsi paling barat dapat mengenal dan mengajar guru-guru yang berada di provinsi paling timur Indonesia. Setiap pengimbasan di daerah yang berbeda memberikan cerita dan pengalaman yang berbeda pula. Bertemu dengan trainer-trainer hebat, dengan kreativitas tanpa batas, mereka membuat suasana pelatihan menjadi tidak terasa berat. Terima kasih kepada pemerintah yang telah mendukung GASING, sehingga dapat membantu meningkatkan numerasi di Indonesia menjadi lebih baik. Dengan GASING, kita meraih mimpi. Dengan GASING, kita mewujudkan cita-cita. Dengan GASING, kita mencintai dan lebih banyak mencintai. GASING siap mengawal Indonesia menuju Indonesia Emas 2045!');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Briliian Prisillia S.H.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Musi Banyuasin yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Briliian Prisillia S.H. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Briliian Prisillia S.H. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Musi Banyuasin', 'Sumatera Selatan', 150000000.0, 0.0, 0, '1234', 'Latar belakang hukum tidak menghalangi langkah saya untuk mendedikasikan diri bagi pendidikan dasar melalui Metode GASING. Di bawah bimbingan langsung dari Prof. Yohanes Surya, saya melihat bagaimana numerasi konkret dapat membangun cara berpikir logis dan analitis anak-anak di pelosok Musi Banyuasin. Menyaksikan senyuman mereka saat menguasai konsep matematika dalam waktu singkat adalah kepuasan batin yang luar biasa bagi hidup saya.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Budiman Saritua Sianipar S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bitung yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Budiman Saritua Sianipar S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Budiman Saritua Sianipar S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bitung', 'Sulawesi Utara', 150000000.0, 0.0, 0, '1234', 'Semuanya berubah ketika tanggal 16 Maret sampai tanggal 1 April 2023 kami direkomendasikan oleh Dinas Pendidikan Kota Kupang untuk mengikuti Pelatihan Pandai Berhitung dengan Metode Gasing (Gampang, Asyik dan Menyenangkan). Rasa takjub ketika pertama kali dalam hidup, saya bisa melihat secara langsung Bapak Profesor Yohanes Surya dan berkesempatan foto bersama Beliau selanjutnya dilatih secara langsung oleh Beliau. Luar biasa, saya bisa bertemu dan diberi motivasi oleh Sang legenda hidup. Gasing sebagai sebuah temuan fenomenal dari Beliau sangat berpengaruh dalam mengubah mindset saya, matematika itu Gampang, Asyik dan Menyenangkan. Saya belajar sebuah metode baru dan saya serius untukterus berlatih selama masa pelatihan. Kemudian Bapa Profesor menyampaikan bahwa peserta pelatihan yang terbaik akan diberi kesempatan untuk bergabung dalam Tim Pengimbasan Nasional Gasing di tempat lain. Saya sangat berbahagia ketika saya mendapat surat dari Yayasan Teknologi Indonesia Jaya (YTIJ) yang tentunya atas rekomendasi dari Bapa Profesor untuk berangkat ke Propinsi Papua Barat Daya tepatnya di Kabupaten Maybrat. Saat di Maybrat, tim kami berkesempatan untuk mendapat Pelatihan Gasing secara langsung dari Bapa Profesor. Pastinya banyak sekali pengetahuan baru dan motivasi yang kami dapatkan dari Beliau sehingga secara pribadi saya lebih termotivasi untuk berbagi kepada guru dan murid di Maybrat. Sebuah hal juga G A S I N G D I H A T I K U/ 1 4 3');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Darlin Adam S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Ambon yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Darlin Adam S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Darlin Adam S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Ambon', 'Maluku', 150000000.0, 0.0, 0, '1234', 'KASIH TRAINER HILDA NAOMI BERNEDIT PAIMA ULI SIREGAR ASAL SMP NEGERI 3 SENTANI KAB. JAYAPURA, PROV. PAPUA G A S I N G D I H A T I K U/ 1 9 6');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Deitawati Dalughu S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Ekonomi', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bitung yang sedang menempuh program studi S2 Pendidikan Ekonomi Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Deitawati Dalughu S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Deitawati Dalughu S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bitung', 'Sulawesi Utara', 150000000.0, 0.0, 0, '1234', 'Mengajar ekonomi membutuhkan fondasi matematika dasar yang kuat. Ketika saya menerapkan Metode GASING di kelas, suasana kaku berganti menjadi tawa dan keceriaan. Anak-anak belajar penjumlahan dan pembagian melalui lagu daerah dan permainan seru. GASING terbukti melatih ketangkasan berpikir kritis dan kreativitas mereka. Saya sangat bersyukur bisa menguasai metode ini untuk mendidik anak-anak daerah asal agar lebih siap menyongsong masa depan.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Devi Rahayu S.Pd.', '/assets/images/trainers/trainer_17.jpg', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Siak yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Devi Rahayu S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Devi Rahayu S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Siak', 'Riau', 150000000.0, 0.0, 0, '1234', 'GASING telah banyak mengubah karakter dan kebiasaanku. Selama 23 tahun hidup, saya adalah orang yang pendiam yang suka berinteraksi dengan orang lain namun merasa kurang nyaman dengan keramaian dan kebisingan. Selama 4 tahun mengajarkan matematika saya selalu merasa kesulitan mengajarkan matematika yang gampang dan menyenangkan. Bahkan sudah coba beberapa metode dan lainnya yang menarik namun tak sanggup berlangsung lama pada siswa saya. Tepat diumur 24 tahun saya dikenalkan GASING oleh Professor Yohannes Surya dan para trainer hebat. Selama saya bersama GASING, saya merasakan keindahan dan bakat lain dalam diri saya. Ternyata GASING mampu mengubahku yang pendiam menjadi pribadi yang ceria dan nyaman dengan keramaian dan kebisingan, ini hal luar biasa. Pelatihan yang hanya 14 hari mampu mengubah karakter saya yang pendiam selama 23 tahun saya hidup. GASING Hebat mampu mengubahku menjadi pribadi yang baik, sabar dan kreatif. GASING mengubahku menjadi guru yang kreatif, asik dan menyenangkan. Para siswa saya ikut menyampaikan perasaan mereka tentang perubahan besar yang ada pada diri saya. Di sekolah kami, panggilan untuk para guru adalah umi dan abi. "Umi yang sekarang kita kenal beda jauh dari umi yang dulu yaaa", "umi yang sekarang setelah pelatihan GASING jadi murah senyum, sabar, dan selama belajar matematika lebih gampang dan menyenangkan", "umi yang sekarang mampu membuat kita jatuh cinta pada Matematika yaa" GASING mampu membawa perubahan besar di sekolah saya. Para guru di sekolah, saya latih berhitung Metode GASING dan belajar cara menciptakan pembelajaran yang menyenangkan melalui GASING. Alhamdulillah setelah 5 hari mengikuti pelatihan GASING, para guru langsung mempraktikannya ke dalam kelas masing-masing. Seluruh kelas Gaduh dan bising dari kelas 1 hingga kelas 6 heboh dengan suasana pembelajaran baru yang');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Dini Haryanti S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Tasikmalaya yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Dini Haryanti S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Dini Haryanti S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Tasikmalaya', 'Jawa Barat', 150000000.0, 0.0, 0, '1234', 'Sebagai guru sekolah dasar, saya selalu mencari metode pengajaran matematika terbaik. GASING menjawab pencarian itu secara tuntas. Anak-anak yang semula menghindari matematika, kini berebutan maju ke depan kelas untuk menjawab soal mencongak. Pengalaman melihat anak-anak pedalaman Tasikmalaya berubah menjadi penuh semangat dan percaya diri telah meneguhkan komitmen saya untuk terus mengabdikan hidup bagi kecerdasan anak-anak bangsa.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Dona Oktafiyenti S.Pd.', '/assets/images/trainers/trainer_19.jpg', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Kepulauan Mentawai yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Dona Oktafiyenti S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Dona Oktafiyenti S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Kepulauan Mentawai', 'Sumatera Barat', 150000000.0, 0.0, 0, '1234', 'Hallo, saya Dona, seorang guru Sekolah Dasar yang bertugas di wilayah 3T, terletak di pedalaman Kabupaten Kepulauan Mentawai, Sumatera Barat. Dahulu, bagi saya, "guru" hanyalah sebuah profesi biasa—bekerja dan esoknya menerima gaji. Namun, setelah menjadi peserta Pelatihan GASING di tahun 2023, saya merasa beruntung sekali bisa bergabung dan dipercaya oleh Prof. Yohanes Surya, Ph.D, sebagai trainer di Gasing Academy. Saya tak bisa menemukan kata yang tepat untuk menggambarkan kekaguman saya terhadap Prof. Yohanes Surya, yang telah mencetuskan Metode GASING yang luar biasa ini. Metode ini benar-benar memberi perubahan besar dalam diri saya. Sebelumnya, saya mengajar sesuai dengan apa yang tertera di RPP atau modul saja, dengan suasana belajar yang kaku dan komunikasi satu arah di dalam kelas. Setelah GASING merasuki diri saya, saya baru tersadar betapa berdosanya saya sebagai guru. GASING mengajarkan saya untuk "mengajar dengan hati" dan merasakan kebahagiaan saat berada di kelas. Selama ini, saya jarang menggunakan hati dan jarang merasa bahagia di kelas. Perlahan, saya mulai memberi hati dan menciptakan suasana bahagia di kelas. Masya Allah, pembelajaran menjadi riuh, siswa dengan mudah menyerap pelajaran, dan tujuan pembelajaran bisa tercapai dengan cepat. Terutama bagi saya, guru di pedalaman, yang harus memiliki strategi khusus untuk menarik perhatian siswa agar mau mengikuti pembelajaran. Saat ini, saya berani memproklamirkan diri sebagai seorang "GURU." Saya percaya diri dan mampu menciptakan suasana belajar yang seru. Siswa-siswi saya bahkan tak menginginkan jam istirahat! Saya mampu menciptakan banyak game dan ice breaking, bahkan siswa-siswa saya tertular semangat tersebut dan mampu membuat game sendiri terkait materi hari itu. Saya pun tidak lagi mengeluh untuk berjalan kaki dua jam menuju bukit demi mendapatkan sinyal 4G untuk mendownload sumber tambahan materi.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Dwi Lintang Kristy Leno S.Pd.', '/assets/images/trainers/default.png', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Nabire yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Dwi Lintang Kristy Leno S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Dwi Lintang Kristy Leno S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Nabire', 'Papua Tengah', 150000000.0, 0.0, 0, '1234', 'Metode GASING memberikan landasan psikologis yang luar biasa dalam proses belajar-mengajar. Dengan pendekatan yang ramah otak, menyenangkan, dan minim tekanan, anak-anak di Nabire mengalami lonjakan pemahaman numerasi yang signifikan. Mereka belajar matematika tanpa rasa cemas, melainkan dengan rasa penasaran yang tinggi. Metode ini benar-benar memanusiakan anak-anak dan membangkitkan kejeniusan terpendam mereka.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Dwi Septy Oktavina S.Pd.', '/assets/images/trainers/trainer_21.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Banyuwangi yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Dwi Septy Oktavina S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Dwi Septy Oktavina S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Banyuwangi', 'Jawa Timur', 150000000.0, 0.0, 0, '1234', 'Matematika adalah mata pelajaran yang paling dianggap sulit dan juga ditakuti oleh peserta didik. Bahkan bukan hanya mata pelajarannya namun gurunya pun dalam pikiran dan penglihatan mereka juga menyeramkan. Namun hadirnya Metode GASING dapat mengubah segalanya. Metode belajar yang Gampang, Asyik, dan Menyenangkan dapat mengubah paradigma bahwa matematika itu sulit menjadi matematika itu sangat mudah dan menyenangkan. Dengan 8C-nya GASING mengubah segalanya baik guru maupun peserta didik. Mulai dari Character, Culture, Critical Thinking, Compassion, Creativity, Collaboration, Communication, Computation Logic. Sebagai seorang trainer saya merasa sangat bersyukur sekali diberi kesempatan untuk mengimbaskan Metode GASING ke seluruh Indonesia. Bisa menularkan ilmu dan juga semangat yang sudah kami dapatkan dari para trainer - trainer kami sebelumnya, dapat ikut andil dalam mewujudkan Indonesia Emas 2045. Alhamdulillah dengan GASING saya bisa sampai ke Kabupaten Gunung Mas, Muna Barat, Buleleng, Pringsewu, Banyuwangi, dan Tegal. Dengan demikian saya bisa mengetahui berbagai karakter masyarakat Indonesia, adat istiadat, serta akan menambah banyak teman, relasi, bahkan menjadi saudara GASING yang ada di seluruh Indonesia. GASING juga sudah banyak mengubah hidup saya, awal mulanya saya guru yang kurang menyenangkan, lalu menjadi guru yang menyenangkan dan selalu dirindukan oleh murid - muridnya, saya yang awalnya tidak hafal kuadrat sehingga mampu menghafal kuadrat sampai 100, yang awalnya pendiam dan malu untuk tampil di depan banyak orang sekarang sudah percaya diri untuk tampil di depan dan berbicara di hadapan banyak orang, saya yang tidak pernah bermimpi untuk dapat pergi keluar Jawa sekarang sudah berapa pulau yang saya datangi. Oleh karena itu GASING sangatlah luar biasa. Terima kasih banyak saya ucapkan untuk Prof. Yohanes Surya, Ph.D. telah menemukan Metode GASING yang sangatlah luar biasa.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Eriya Gusmara S.Pd.', '/assets/images/trainers/trainer_22.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Lampung Barat yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Eriya Gusmara S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Eriya Gusmara S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Lampung Barat', 'Lampung', 150000000.0, 0.0, 0, '1234', 'Setiap pengalaman hidup datang dengan membawa suatu alasan. Dari setiap pengalaman yang saya dapati terutama selama menjadi guru, saya banyak merasakan suka duka berproses dan tak jarang saya merasa jenuh. Sampai pada akhirnya GASING hadir memberikan perubahan besar dalam hidup saya. GASING meyakini saya bahwa tidak ada yang kebetulan, melainkan ini adalah jalan dari Tuhan untuk membentuk diri saya menjadi guru yang sesungguhnya. Sebelum mengikuti pelatihan metode matematika GASING, saya adalah seorang guru yang hanya menjalankan prosedur kerja dan tugas pokok dengan kaku. Saya belum sepenuhnya menemukan bahwa keterampilan 8C itu sangat diperlukan dalam menjalankan profesi saya bahkan sangat penting dalam kehidupan sehari-hari. 8C yang dimaksud adalah communication, collaboration, critical thinking, creativity, character, computational logic, culture, dan compassion. Keterampilan 8C tersebut saya dapati dari Metode GASING. Berdasarkan keterampilan 8C tersebut, hal baru yang sangat saya rasakan adalah mendidik dengan hati. Setiap melakukan pengimbasan Metode GASING, sy diberikan segenap pembinaan baik itu materi, kepribadian, semangat, kreatifitas, dan bahkan cara menyayangi anak-anak dengan segenap hati. Hal inilah yang saya alami tidak saya dapatkan dari pengalaman-pengalaman sebelumnya. Dalam setiap pengimbasan di kabupaten/kota lain, saya dan rekan-rekan trainer dapat menjalin persaudaraan dan persahabatan yang begitu hangat. Saat ini bahkan kami selalu berkolaborasi, komunikasi dan berbagi melalui group jejaring sosial. Dalam forum ini ilmu-ilmu terbaharui dengan cepat, ide-ide kreatif untuk melayani peserta didik begitu kaya. Pekerjaan saya pun sangat terbantu, menjadi ringan, dan menyenangkan. Saat ini setiap akan mengajar saya penuh semangat dan tidak sabar untuk bermain bersama anak, tidak sabar untuk berbagi');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Erlin Nurrosyida S.Pd.', '/assets/images/trainers/trainer_23.jpg', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Sumedang yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Erlin Nurrosyida S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Erlin Nurrosyida S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Sumedang', 'Jawa Barat', 150000000.0, 0.0, 0, '1234', 'Dear Bapak Presiden Jokowi dan Bapak Menko Luhut, Perkenalkan, saya Erlin Nurrosyida, guru SD dari Kabupaten Sumedang, yang kini Alhamdulillah diberi kesempatan dan kepercayaan oleh Prof. Yohanes Surya untuk menjadi trainer GASING. Awalnya, saat mendengar tentang GASING, saya berpikir, "Ah, itu kan nama sebuah mainan," dan mengira bahwa pelatihan GASING adalah tentang permainan tradisional. Namun, ketika nama GASING disandingkan dengan Prof. Yohanes Surya, Ph.D, saya menyadari bahwa GASING pasti ada kaitannya dengan Fisika atau Matematika, mengingat beliau adalah seorang ahli di bidang Fisika yang saya kenal sejak SMA. Saya masih ingat, pada 4 Februari 2023, saya menggantikan rekan saya yang sakit untuk mengikuti pelatihan Metode GASING. Meskipun saat itu saya juga dalam kondisi tidak sehat, semangat dan rasa penasaran untuk bertemu langsung dengan Prof. Yohanes Surya membuat saya terus maju, karena sebelumnya saya hanya mengenalnya dari buku-buku Fisika. Empat belas hari berlalu begitu cepat selama pelatihan GASING. Banyak hal baru yang saya temukan dalam diri saya. Saat mengikuti pelatihan, saya merasa seperti kembali menjadi murid. GASING juga membuat karakter saya berubah; sebelumnya, saya adalah guru yang gampang marah jika ada murid yang lambat atau tidak bisa. Kini, saya belajar untuk lebih sabar dalam menghadapi mereka. Saya juga jarang melakukan ice breaking atau permainan di kelas karena merasa malu, terutama jika harus bergerak seluruh tubuh. Namun, berkat GASING, saya kini lebih percaya diri, bahkan mungkin saya sering berperilaku konyol! Melalui GASING, saya juga belajar bagaimana pendekatan kepada murid, meraih hati mereka agar tertarik pada kita dan Matematika, sehingga pelajaran menjadi Gampang, Asyik, dan Menyenangkan. Selama menjadi peserta, saya banyak merenung dan merasa terharu ketika menyadari bahwa salah satu anak didik saya adalah anak piatu yang ternyata memiliki gangguan penglihatan. Saya baru');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Farny Mamonto S.Pd.', '/assets/images/trainers/default.png', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bitung yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Farny Mamonto S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Farny Mamonto S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bitung', 'Sulawesi Utara', 150000000.0, 0.0, 0, '1234', 'Guru Monster Perempuan, saya mendengar dari seorang guru jika anak-anak dikelasnya memberikan saya julukan seperti itu walaupun saya tidak mengajar dikelas mereka. Anak-anak itu takut ketika mendengar jika naik kelas 8 sayalah yang akan menjadi guru matematika mereka. Saat mendengar itu, sejujurnya hati kecil saya sedikit terluka. Saya adalah guru yang kaku, dingin, dan semenakutkan itu ternyata. sampai suatu hari saya diajak mengikuti pelatihan "Bitung Pande Barekeng, melalui metode GASING" selama 15 hari. Dalam perjalanan ke tempat pelatihan Kepala sekolah saya berkata "Nanti kalian akan belajar berhitung pakai jari". Saya sempat bingung kenapa berhitung pakai jari saja harus sampai 15 hari. Sampai ketika memulai pelatihan, aula yang besar dan dipeserta gurunya 300-an orang. pikiranku, pasti pelatihan ini tidak akan maksimal. tapi ternyata saya salah. ketika kegiatan dimulai dari Pretest tiba-tiba kami mulai terpacu untuk memberikan yang terbaik. sampai memasuki materi tak disangka banyak hal menyenangkan yang kami lakukan. Tibalah waktu pengimbasan, saya ingat waktu itu kami membawa 7 siswa, saya bisa melihat siswa yang saya pilih awalnya berat berhadapan dengan saya mungkin mereka masih terngiang-ngiang dengan julukan saya. tapi hal itu tak berlangsung lama karena besoknya mereka langsung mendekati saya duluan dan memberikan senyuman mereka. Selama pelatihan banyak hal yang saya terima dan pelajari, Bagaimana menyampaikan materi dengan benar, bagaimana membaca suasana siswa yang mungkin terlalu penat, dan yang paling penting bagaimana mengajar dengan hati. Selesai pelatihan tak disangka saya dipanggil mengikuti Pengimbasan Nasional di Makassar, itu adalah pengalaman pertama saya sebagai trainer gasing. Saya seorang guru SMP yang terbiasa bertemu dengan siswa yang sudah mengerti banyak hal sekarang dihadapkan dengan siswa SD yang lebih ingin bermain, ingin selalu diperhatikan. Di pelatihan ini saya mempunyai seorang siswa yang spesial, Dia butuh perhatian khusus namanya Nabila. Nabila anak kelas 4 SD, tapi belum mengenal angka bahkan menulis namanya saja dia belum bisa dan dari gurunya diketahui jika dia menderita diseklesia. hari demi hari saya jalani dengan Nabila menjadi perhatian yang lebih khusus dibandingkan teman yang lain. G A S I N G D I H A T I K U/ 1 4 8');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Fransiska Carolin Mayabubun S.Pd., Gr.', '/assets/images/trainers/trainer_25.jpg', 'S2 Pendidikan Geografi', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Jayapura yang sedang menempuh program studi S2 Pendidikan Geografi Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Fransiska Carolin Mayabubun S.Pd., Gr. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Fransiska Carolin Mayabubun S.Pd., Gr. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Jayapura', 'Papua', 150000000.0, 0.0, 0, '1234', 'GASING luar biasa mengubah hidup saya. Saya, Fransiska Carolin Mayabubun/Kbarek, adalah salah satu guru PPPK asli Papua di SDN Inpres Megapura, Kota Jayapura, Papua. Perjalanan ini dimulai dari Pelatihan GASING pada akhir Desember 2023, yang merupakan kerjasama antara Dinas Pendidikan Kota Jayapura dan Gasing Academy. Suatu kehormatan bagi saya bisa menerima materi Matematika GASING, "Gampang, Asik, Menyenangkan," langsung dari Profesor Yohanes Surya dan tim. Bahkan, saya dinilai sebagai salah satu peserta terbaik di antara banyak guru lainnya. Setelah pelatihan, saya mendapatkan kesempatan untuk mengimbaskan Metode GASING ke berbagai daerah di luar Kota Jayapura. Pengimbasan pertama saya dilakukan di luar Kota Jayapura, yaitu bagi para guru dan siswa di Puncak Jaya, Provinsi Papua Tengah, pada tahun 2024, yang diadakan di Timika. Pengalaman ini sangat berharga karena saya bisa mengeksplorasi potensi diri dengan Metode GASING dan mengasah keterampilan "8C," yang membuat saya menjadi guru yang dicintai siswa-siswa saya di kelas 5 dan 6 SD Kwamki Lama. Kebanggaan seorang guru adalah ketika melihat anak didiknya mandiri dan percaya diri dalam menjawab soal, dan itu terbukti melalui Metode GASING. Pengimbasan kedua membawa saya ke Kabupaten Nduga, Provinsi Papua Pegunungan. Di sana, saya mengajar di kelas khusus yang terdiri dari siswa kelas 1 hingga kelas 6. Kelas saya bisa diibaratkan sebagai miniatur sekolah, karena semua tingkatan ada di dalamnya. Semua siswa sangat antusias dan bahagia belajar dengan Metode GASING dari hari pertama hingga hari terakhir. Mereka mampu membuat soal dan menjawabnya dengan tepat. Saya merasa sangat bahagia berada di tengah-tengah siswa yang begitu tulus, terutama siswa kelas 1. Sebagai anak asli Papua, saya bersyukur dapat berkontribusi bagi kemajuan pendidikan di Tanah Papua melalui program Matematika GASING. Terima kasih yang tak terhingga saya sampaikan kepada Prof. Yohanes Surya.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Fredrik Aya Semunya S.Pd.', '/assets/images/trainers/trainer_26.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Maybrat yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Fredrik Aya Semunya S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Fredrik Aya Semunya S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Maybrat', 'Papua Barat', 150000000.0, 0.0, 0, '1234', 'Nama saya Fredrik. Saya adalah seorang guru ASN di SD YPPK Seya, Distrik Mare, Kabupaten Maybrat, Provinsi Papua Barat Daya. Aktivitas saya dalam mengajar matematika di sekolah sebelumnya menggunakan cara perhitungan tradisional. Pembelajaran matematika yang diterapkan oleh Kementerian Pendidikan di era presiden sebelumnya kurang kondusif, disebabkan oleh metode yang monoton, sehingga siswa merasa takut, bosan, dan jenuh. Pada Mei 2023, Profesor Yohanes Surya, Ph.D., datang ke Kabupaten Maybrat dengan membawa Metode GASING (Pembelajaran Matematika yang Asik, Gampang, dan Menyenangkan). Dalam pelatihan GASING tersebut, saya mengalami perubahan signifikan dalam pengajaran matematika. Dulu, metode saya monoton dan menggunakan cara berhitung dari belakang. Namun, dengan GASING, proses berhitung dimulai dari depan, dan pendekatan saya yang langsung menunjukkan bentuk abstrak ternyata kurang tepat. Ketika saya mengenal GASING, prosesnya luar biasa. Matematika hadir dalam kehidupan kita dan diterapkan melalui GASING dalam bentuk konkret (benda kehidupan masyarakat), abstrak (simbol), dan mencongak (keputusan yang cepat). Tiga hal ini sangat berpengaruh dalam pengajaran matematika. Kita sebagai manusia tidak dapat terlepas dari matematika, karena kita harus belajar untuk menjadi orang yang adil, jujur, dan bijaksana dalam kehidupan sehari-hari. Pembelajaran Metode GASING sangat mengubah pribadi saya. Dulu, saya dianggap sebagai guru yang galak. Namun, setelah mengenal GASING, saya mengajar dengan hati, dan kepribadian saya berubah total. Saya diberikan kepercayaan oleh Profesor untuk mengajar GASING ke seluruh Nusantara, yang saya anggap sebagai karunia dari Tuhan. Perubahan karakter saya membuat saya, sebagai orang Papua, dihargai saat mengajar di luar pulau Papua. Mereka menganggap bahwa kami, orang Papua, tidak bodoh atau ketinggalan.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Frilly Charolina Rengkuan S.Pd.', '/assets/images/trainers/trainer_27.jpg', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bitung yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Frilly Charolina Rengkuan S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Frilly Charolina Rengkuan S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bitung', 'Sulawesi Utara', 150000000.0, 0.0, 0, '1234', '"Ibu yang kemarin Guru Monster itu yah?" Saya tersenyum dan mendekati anak-anak itu sambil berbicara layaknya teman mereka "Memang ibu terlihat seperti monster?" dengan serentak mereka tertawa dan bilang "Tidaaak, Ibu cantik dan baik" kami pun tertawa bersama-sama. Di sekolah, siswa ketika melihat saya dia melompat mendekatiku sambil berteriak "Enci, so ada? P lama skali doe. So kangen sekali torang''. (Ibu sudah datang? Sudah lama sekali, kami sangat kangen"). Itu adalah ungkapan dari siswa yang dulu saat melihatku takut dan lari. "Ibu kapan lagi kita belajar GASING?" pertanyaan seperti ini sudah sering terdengar Sejak mengikuti pelatihan Pandai Berhitung dengan Metode GASING (Gampang, Asyik dan Menyenangkan), dalam 2 tahun terakhir banyak perubahan yang saya alami. Salah satunya adalah ungkapan manis dari siswa-siswa di sekolahku ataupun peserta pelatihan di daerah. Julukan yang pernah disematkan padaku sebagai "Guru Monster Perempuan" kini tidak ada lagi. Siswa mulai menunggu dan meminta diajarkan, bertemu denganku mereka banyak mengeluarkan senyuman dan tertawa. Inilah yang diimpikan setiap guru, mengajar itu tidak perlu kaku harus duduk ditempat duduk dengan bernyanyi, bising, berlari kesana kemari itu adalah salah satu proses pembelajaran yang akan menuntun anak menemukan dirinya sendiri. Dengan metode ini banyak anak yang mau membuka diri, percaya diri menunjukkan kemampuan yang selama ini mereka sembunyikan. Pembelajaran matematika yang selalu jadi momok menjadi hal yang ditunggu mereka. Dari pelatihan ini saya menyadari bahwa guru bisa berhasil jika bisa merebut hati siswanya. Siswa yang nyaman dengan gurunya akan kreatif menciptakan sesuatu dari budaya setempat, berkomunikasi dan berkolaborasi, menyelesaikan soal dengan');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Fryda Christiany Moan S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Mappi yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Fryda Christiany Moan S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Fryda Christiany Moan S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Mappi', 'Papua Selatan', 150000000.0, 0.0, 0, '1234', 'Mengabdi di Mappi Papua Selatan menyadarkan saya akan pentingnya metode pengajaran matematika yang kontekstual dan tulus. Melalui Metode GASING, saya menyaksikan mukjizat pendidikan: anak-anak pedalaman yang semula kesulitan mengenal angka, dalam hitungan minggu mampu mencongak penjumlahan dan perkalian dengan sangat cepat. Senyuman tulus mereka di tengah segala keterbatasan adalah alasan utama mengapa saya terus berjuang.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('I Gede Fajar Dian Mahendra S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Buleleng yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, I Gede Fajar Dian Mahendra S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, I Gede Fajar Dian Mahendra S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Buleleng', 'Bali', 150000000.0, 0.0, 0, '1234', 'Hal tak terduga menghampiri hidup saya. Tak pernah terpikirkan saya akan menjadi seorang trainer. Trainer yang siap untuk berbagi. Trainer yang siap untuk membantu. Trainer yang ingin memberikan yang terbaik untuk pendidikan Indonesia. Terdengar sangat klise dan berkesan mengada-ada, tapi inilah saya setelah berjumpa dengan GASING. Awal jumpa dengan GASING, saya masih merasa canggung dengan diri saya. Canggung untuk berkomunikasi dan ragu untuk bertindak diantara peserta yang baru saya kenal. Saya sering beranggapan hal yang saya lakukan akan dinilai kurang baik oleh orang lain. Hingga akhirnya GASING memberikan kesempatan kepada saya untuk menjadi diri saya sendiri. Saya adalah seorang guru laki-laki yang suka berjoged. berdendang, dan bernyanyi. Bayangkan saja apakah tidak dinilai sebagi hal yang aneh ketika seorang guru laki-laki berjoged dan berdendang dalam proses pembelajaran. Namun, GASING menyediakan tempat buat saya untuk berinovasi, berkreativitas, berjoged, dan berdendang saat belajar. Ternyata pembelajaran menjadi lebih seru dan menyenangkan. Materi pun dapat diterima siswa dengan lebih baik. Ternyata tak seburuk yang saya bayangkan. Saya sadari bahwa musuh saya adalah diri saya sendiri. Musuh yang selalu membuat saya takut dan menghalangi potensi yang ada dalam diri saya. Kini saya berusaha untuk menjadi diri saya sendiri. Selalu menyikapi suatu hal dari sisi positifnya. Ini menjadi kekuatan bagi saya untuk menjadi lebih berani, lebih percaya diri, yakin dengan diri saya sendiri, dan selalu bersyukur dengan apa yang saya miliki. Sebagai seorang trainer, saya ingin membantu, berbagi, dan memberikan yang terbaik kepada bapak/ibu guru serta anak-anak yang masih takut dan kurang yakin dengan diri mereka sendiri agar menjadi lebih berani, bersemangat, dan yakin dengan diri sendiri bahwa kita bisa. Selalu berusaha untuk upgrade diri menjadi versi');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Indry Wenno S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Jayapura yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Indry Wenno S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Indry Wenno S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Jayapura', 'Papua', 150000000.0, 0.0, 0, '1234', 'Contents Adi, Si Istimewaku Jelvyna Sumongga, S.Pd., Gr. Gasing Mengubah Diriku Jenet Ngaderman Bapak Pendidikan Orang Papua Julfin Jessica Mirino Selamat Ulang Tahun Bapak Prof. Juma Iriyanto Saleh Gasing Menjadikan Saya Sebagai Guru Yang Sebenarnya Guru Muhamad Imin Jaya Gasing dan Ceritaku Ocevina Dimor Metode Gasing Telah Merubah Pola Pikir Pembelajaran Matematika di Aru Restu Pangestuti Memberi Dari Hati Rini Lestari, S.Pd., Gr. Bersyukur Diberi Kesempatan Mengenal Gasing Rr. Selvi Amelia Rahmawati Gasing Merubahku Sri Handayani Sianipar 226 Gasing Menyatukan Budaya dan Pengetahuan Verawati Cono S.T., M.Pd. 228 Semua Berkat Gasing Yohana Christina Rahangmetan Gasing Tidak Memandang Fisik');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Inggrid Sitanala S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bitung yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Inggrid Sitanala S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Inggrid Sitanala S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bitung', 'Sulawesi Utara', 150000000.0, 0.0, 0, '1234', 'Sebagai guru matematika, saya sering merasa bersalah melihat anak-anak kesulitan memahami rumus yang abstrak. Namun, Metode GASING mengubah segalanya dengan menghadirkan matematika konkret yang gampang dipahami. Ketika anak-anak Bitung mulai menikmati mencongak sambil bernyanyi dan bergoyang, saya tahu bahwa ini adalah revolusi pendidikan yang sesungguhnya. Terima kasih Prof. Yohanes Surya atas ilmu yang sangat berharga ini.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Jein Anggreini Sarlota Waghe S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bitung yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Jein Anggreini Sarlota Waghe S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Jein Anggreini Sarlota Waghe S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bitung', 'Sulawesi Utara', 150000000.0, 0.0, 0, '1234', 'Matematika GASING mengajarkan bahwa pendidikan adalah tentang menyentuh hati anak-anak terlebih dahulu sebelum menyentuh pikiran mereka. Pelatihan ini melatih kami menjadi guru yang kreatif, sabar, dan penuh kasih sayang. Ketika anak-anak didik saya di Sulawesi Utara berhasil memecahkan soal pembagian sulit dengan gembira, saya menyadari betapa besarnya potensi anak-anak Indonesia jika dididik dengan metode yang tepat.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Jeni Arianti Pa Nyola S.Pd.', '/assets/images/trainers/default.png', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Lanny Jaya yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Jeni Arianti Pa Nyola S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Jeni Arianti Pa Nyola S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Lanny Jaya', 'Papua Pegunungan', 150000000.0, 0.0, 0, '1234', 'Melalui kacamata psikologi pendidikan, Metode GASING berhasil memicu motivasi intrinsik dan rasa percaya diri anak-anak di Lanny Jaya. Pendekatan belajar sambil bermain ini menghilangkan blok mental terhadap matematika. Anak-anak yang tadinya pasif kini aktif berpartisipasi dan berani tampil di depan kelas. GASING membuktikan bahwa dengan ketulusan dan cara mengajar yang menyenangkan, anak-anak pedalaman pun mampu berprestasi tinggi.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Jeni Kada Saripi S.Pd.', '/assets/images/trainers/trainer_34.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Nabire yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Jeni Kada Saripi S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Jeni Kada Saripi S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Nabire', 'Papua Tengah', 150000000.0, 0.0, 0, '1234', 'Seperti yang kita ketahui bersama, matematika merupakan pelajaran yang sangat ditakuti oleh sebagian orang. Namun, hal ini tentu tidak berlaku bagi kita yang mencintai matematika. Salah satu orang yang mencintai matematika adalah Prof. Yohanes Surya. Beliau tidak hanya mencintai matematika, tetapi juga sungguh-sungguh mencintai anak-anak bangsa Indonesia. Bukti nyata cinta beliau kepada anak-anak bangsa adalah dengan menghadirkan Metode GASING (Gampang Asyik dan Menyenangkan). Saya sangat bersyukur bisa mendapatkan metode ini melalui pelatihan di Kabupaten Nabire Fase 1. Ternyata, matematika menjadi sangat mudah dipelajari dengan Metode GASING. Saya bahkan bisa sampai ke tahap mencongak, yang sungguh luar biasa. Saya percaya, jika saya bisa merasakan perubahan baik dari segi pengetahuan maupun keterampilan mengajar (8C), orang lain juga pasti merasakan hal yang sama. Terima kasih banyak kepada Prof. dan tim yang telah menghadirkan perubahan di daerah-daerah 3T di seluruh Indonesia, khususnya Papua. Teruslah menebarkan Metode GASING di seluruh Indonesia untuk mewujudkan Indonesia yang pandai berhitung. Salam GASING!');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('John Richard Huwae S.Pd.', '/assets/images/trainers/trainer_35.jpg', 'S2 Pendidikan Fisika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Ambon yang sedang menempuh program studi S2 Pendidikan Fisika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, John Richard Huwae S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, John Richard Huwae S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Ambon', 'Maluku', 150000000.0, 0.0, 0, '1234', 'Sebagai seorang trainer Metode GASING, saya memiliki kesempatan berharga untuk berbagi pengetahuan dan pengalaman dalam pendidikan. Metode ini tidak hanya mengajarkan matematika, tetapi juga memberikan cara baru dalam mengajar yang interaktif dan menyenangkan. Setiap kali saya berdiri di depan kelas, saya merasakan semangat dan antusiasme para guru yang siap belajar. Mengajar dengan hati adalah prinsip yang selalu saya pegang. Saya percaya bahwa seorang pendidik tidak hanya menyampaikan materi, tetapi juga membangun hubungan yang kuat dengan muridnya. Metode GASING memberikan kesempatan bagi guru-guru untuk menyentuh jiwa para siswa dan membuat mereka lebih tertarik pada pelajaran, terutama dalam matematika yang sering dianggap sulit. Saya yakin bahwa jika setiap guru di Indonesia mengajar dengan hati dan menerapkan metode yang inovatif, kita dapat menciptakan generasi yang lebih cerdas dan kreatif. Metode GASING bukan hanya sekadar alat pengajaran, tetapi juga kunci untuk membuka pintu perubahan dalam dunia pendidikan. Pengalaman saya sebagai trainer Metode GASING adalah tentang membangun hubungan, menciptakan inspirasi, dan menanamkan harapan di hati para pendidik. Dengan setiap GASING yang berputar, saya percaya kami sedang menyalakan semangat baru dalam pendidikan. Langkah kecil ini dapat berdampak besar bagi masa depan Indonesia, dan saya berkomitmen untuk terus berkontribusi dalam mengubah wajah pendidikan di tanah air. John Huwae, S.Pd - Trainer Kota Ambon Bersama GASING Bisa Mengubah Segalanya');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Jonatan Hasudungan Sihombing S.Pd.', '/assets/images/trainers/trainer_36.jpg', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Dairi yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Jonatan Hasudungan Sihombing S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Jonatan Hasudungan Sihombing S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Dairi', 'Sumatera Utara', 150000000.0, 0.0, 0, '1234', 'Suatu kebanggaan bagi saya bisa bergabung bersama dengan Tim GASING. Saya yang bekerja di pedesaan jauh dari perkotaan dan yang kemudian dipercaya menjadi seorang trainer ke berbagai daerah di Indonesia merupakan suatu berkat yang sangat besar yang saya terima. Orang desa bisa pergi kemana- mana, dibiayai.. Wahh, luar biasa berkat Tuhan. Awal mengenal Metode GASING ini, saya sebagai peserta tidak terlalu antusias karna.. yahh sudah banyak metode-metode di luar sana yang memudahkan untuk belajar Matematika. Namun, hari demi hari terlewati saya menjadi sangat antusias karna ternyata ini sangat berbeda dengan metode lainnya. "Ohh..", itu merupakan reaksi saya ketika semakin mengerti dengan konsepnya. Ahh.. sangat menyenangkan bisa merasakan sendiri momen "Eureka" itu. Hal yang sama juga terjadi saat saya menjadi trainer di beberapa daerah, saya menemukan raut wajah yang sama dengan saya saat menjadi peserta. Wajah-wajah bingung, cuek. Tapi ini menjadi suatu tantangan bagi saya. Kalau saya bisa merasakan momen itu, maka murid-murid dan guru yang saya hadapi ini harus bisa juga merasakan momen "Eureka" tersebut. Selain momen "Eureka", saya juga agak sedikit kaget dengan perubahan dari diri saya sendiri. Selama ini, murid-murid dan guru lain mengenal saya sebagai pribadi yang kalem dan jaim. Ternyata setelah mengenal GASING, saya berubah menjadi guru yang asyik, gak jaim-jaim lagi.. plus bisa joget, hahaha.. Sebagai bonus, saya bisa menikmati perjalanan ke daerah yang tidak terpikirkan sebelumnya untuk saya jalani. Mulai dari Lembata (NTT), Timika (Papua Tengah), Buleleng (Bali) dan Jayawijaya (Papua Pegunungan), serta menemukan orang- orang dengan karakteristik yang berbeda-beda, ritual adatnya, mengenakan pakaian khasnya, dan lain sebagainya. Dari semua itu, saya mau memberi diri untuk berproses');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Joni Wanri Simbolon S.Pd.', '/assets/images/trainers/default.png', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Samosir yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Joni Wanri Simbolon S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Joni Wanri Simbolon S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Samosir', 'Sumatera Utara', 150000000.0, 0.0, 0, '1234', 'Banyak hal yang terlintas di pikiran. Apakah bisa mengajar mereka dan apakah mereka akan paham apa yang akan saya berikan. Pikiran itu semakin nyata ketika sampai kedaerah tersebut. Ditambah dengan orang yang kita jumpa sangat bertolak belakang dengan apa yang ada di angan-angan. Apakah ini yang akan saya ajar? Apakah saya bisa? Pikiran itu terlintas dikepala ketika melihat orang-orang yang saya ajari adalah anak yang berkebutuhan khusus. Beragam anak yang di diagnosa berkebutuhan yang sama sekali belum pernah aku temui sebelumnya. Saya pesimis, saya merasa tidak yakin dengan apa yang akan saya hadapi saat ini. Ada anak ADHD, anak yang hyperaktif, ada anak yang kurang motivasi belajar, anak yang memiliki dunia sendiri dan banyak lagi. Hari pertama saya ingin menyerah, tapi karena melihat anak-anak yang memiliki kekurangan demikian dan juga dukungan rekan, saya mencoba mengajar anak-anak tersebut. Banyak Teknik yang saya coba, banyak cara yang saya lakukan serta banyak hal yang mungkin tidak terpikir sebelumnya saya coba. Mungkin di awal memang sedikit kewalahan, tapi seiring berjalannya waktu bisa menghadapinya. Anak yang hyperaktif bisa serius belajar, anak yang ADHD makin percaya diri dan bisa melakukan hal yang disenangi, anak yang berbicara sendiri perlahan bisa kembali normal dan menjadi periang. GASING tidak hanya mengajarkan materi matematika kepada anak-anak, tapi GASING memiliki sesuatu hal yang tidak');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Kadek Ashadi Putra S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Buleleng yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Kadek Ashadi Putra S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Kadek Ashadi Putra S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Buleleng', 'Bali', 150000000.0, 0.0, 0, '1234', 'Melihat kegembiraan anak-anak Buleleng saat belajar mencongak cepat lewat Metode GASING merupakan kepuasan terbesar bagi saya sebagai seorang guru SD. Konsep visual yang matang dari metode ini membuat matematika tidak lagi abstrak dan membosankan. GASING mengajarkan kami untuk terus berinovasi dalam mengajar, menanamkan kedisiplinan serta rasa percaya diri yang tinggi pada generasi muda.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('La Ode Maharudin S.Pd.', '/assets/images/trainers/trainer_39.jpg', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Buton Selatan yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, La Ode Maharudin S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, La Ode Maharudin S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Buton Selatan', 'Sulawesi Tenggara', 150000000.0, 0.0, 0, '1234', 'Nama saya La Ode Maharudin lahir di Lakulepa, 24 Desember 1995. Saya adalah seorang guru di SD Negeri 1 Poogalampa Kecamatan Batauga Kabupaten Buton Selatan. Sejak terpilihnya menjadi trainer, sudah beberapa daerah yang saya kunjungi untuk melakukan pengimbasan mulai dari wilayah Indonesia bagian timur, tengah, dan juga bagian barat. Dengan kepercayaan dan kesempatan yang diberikan oleh Prof. Yohanes Surya, Ph.D menjadikan saya mendapatkan banyak pengalaman berharga. Beliau adalah sosok yang inspiratif bagi banyak orang. Dengan pendekatan yang penuh semangat dan dedikasi, beliau menunjukkan bahwa pengetahuan dan kebaikan dapat saling melengkapi. Melalui ajarannya, saya diajarkan untuk tidak hanya mengejar kepentingan pribadi, tetapi juga untuk memberikan dampak positif bagi orang banyak. Menebar kebaikan memang bisa menciptakan efek positif yang berlipat. Setiap tindakan baik bisa memicu kebaikan lain baik untuk diri sendiri maupun orang lain. Ketika kita berbuat baik, kita tidak hanya membuat orang lain bahagia, tetapi juga meningkatkan kebahagiaan dan kepuasan dalam diri kita. Perjalananku yang luar biasa yang lahir dari latar belakang keluarga sederhana hingga menjadi Trainer GASING benar-benar menginspirasi saya. Melalui pengalaman ini, saya tidak hanya mendapatkan pengetahuan baru, tetapi juga kesempatan untuk berinteraksi dengan orang-orang hebat. Ada banyak hal yang saya pelajari ketika berinteraksi dengan guru-guru juga peserta didik yang ada di setiap daerah diantaranya: budaya lokal, mengalami cara hidup, makanan, dan festival unik dari daerah yang dikunjungi; interaksi sosial, bertemu dan berbicara dengan orang-orang baru, yang bisa membuka wawasan dan perspektif baru; keindahan alam, menyaksikan pemandangan alam yang menakjubkan, dari pegunungan hingga pantai; pembelajaran sejarah, mengetahui lebih dalam tentang sejarah dan warisan suatu daerah.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('La Samaudin S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Buton yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, La Samaudin S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, La Samaudin S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Buton', 'Sulawesi Tenggara', 150000000.0, 0.0, 0, '1234', 'GASING telah meruntuhkan dinding ketakutan anak-anak terhadap matematika di Buton. Dengan metode konkret-abstrak yang terstruktur, anak-anak memahami konsep berhitung secara mendalam, bukan sekadar menghafal. Pengalaman mengajarkan lagu pasangan sepuluh dan melihat mata anak-anak berbinar gembira saat berhasil mencongak adalah momen terbaik dalam karier keguruan saya.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Leiden Levita Sahensolar M.Pd.K.', '/assets/images/trainers/trainer_41.jpg', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Tolikara yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Leiden Levita Sahensolar M.Pd.K. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Leiden Levita Sahensolar M.Pd.K. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Tolikara', 'Papua Pegunungan', 150000000.0, 0.0, 0, '1234', 'Entah dari mana saya harus memulai, tetapi dengan ketulusan dan rasa bangga, saya ingin menuliskan setiap kata di selembar kertas kosong ini. Saya ingin menyampaikan kebanggaan saya menjadi bagian dari keluarga besar GASING dan menceritakan kepada dunia bagaimana GASING mengubah hidup saya. Saya adalah seorang guru agama Kristen yang saat ini mengajar di pedalaman Papua Pegunungan, tepatnya di Kabupaten Tolikara, Distrik Wakuwo. Sejak masa sekolah, matematika adalah pelajaran yang sangat mengintimidasi saya. Saya masih ingat betapa kejamnya perkataan guru matematika saya saat SMP, yang berkata bahwa saya tidak layak berada di kelas unggulan karena tidak memahami pelajaran matematika yang dia berikan. Sejak saat itu, saya sangat terpukul dan tidak menyukai matematika. Namun, semuanya berubah beberapa bulan yang lalu. Saya menjadi salah satu peserta Pelatihan GASING Kabupaten Tolikara Batch 2. Sejak hari pertama, saya sudah merasakan bahwa GASING berbeda. Saat masuk ke dalam kelas, para trainer menyambut kami dengan senyuman hangat setiap harinya. Pelajaran di kelas sangat menyenangkan, dan semuanya terasa mudah dipahami berkat Metode GASING. Yang paling membuat hati saya terenyuh adalah ketulusan para trainer dalam mengajari kami. Mereka tidak menertawakan ketidaktahuan kami dan tidak menganggap remeh pertanyaan- pertanyaan sepele kami. Ketika kami belum memahami pelajaran yang diberikan, mereka dengan sabar menjelaskannya kembali. Saya tahu mereka kelelahan, namun tidak pernah sekalipun mereka menunjukkan wajah muram di depan kami. Saya sungguh melihat ketulusan dalam mengajar dari para trainer GASING. Tujuh belas hari pelatihan telah mengubah hidup saya. Bukan hanya soal kecintaan terhadap matematika, tetapi GASING juga mengajarkan saya bagaimana mengajar dengan hati, tidak bersungut- sungut meski lelah, serta membangun keceriaan dan sukacita dalam kelas.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Lien Malinda S.Pd.', '/assets/images/trainers/trainer_42.jpg', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Sumedang yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Lien Malinda S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Lien Malinda S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Sumedang', 'Jawa Barat', 150000000.0, 0.0, 0, '1234', '36 GasingKu di Hati Eris Riska Aryati Contents Bertemu Prof. Yohanes Surya di Sumedang Erlin Nurrosyida, S.Pd Menemukan Makna Compassion yang Sesungguhnya Sebagai Pendidik Ester P.T Siboro, S.Pd Memberikan yang Terbaik untuk Indonesia Fernando JH. Sianturi, S.Pd Metode yang Membuat Lebih Percaya Diri Feronika Silitonga Si Cempreng Terbang Bersama GASING Gresylia Kristiyanti, S.Pd Semoga Prof Yo. Ngga Salah Pilih! Handri Yanto Kerennya Gasing Hanipah Tanjung Pengalaman Mengikuti Pelatihan Metode Gasing Matematika Hirim Lasmarito Purba Gasing Mengubah Saya Menjadi Guru SD Yang Sesungguhnya Isa Widari Br Hombing Matematika Gasing Mengubah Mindset Belajar Juster S. Siburian,S.Pd 65 Pengalaman Belajar Metode Gasing Lamtobat Sihombing 68 Pengalaman Ber-Gasing');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Lisbet Evy Sartika Simamora S.Th.', '/assets/images/trainers/default.png', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Dairi yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Lisbet Evy Sartika Simamora S.Th. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Lisbet Evy Sartika Simamora S.Th. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Dairi', 'Sumatera Utara', 150000000.0, 0.0, 0, '1234', 'Di dunia pendidikan, saya telah menemukan sebuah pengalaman yang membuka hati dan pikiran saya: Metode GASING yang diperkenalkan oleh Prof. Yohanes Surya, Ph.D. Melalui pendekatan ini, saya menyaksikan bagaimana kehadiran seorang guru yang menggabungkan hati dan akal secara bersamaan dapat mengubah cara anak-anak belajar. Saya masih ingat dengan jelas saat melihat anak-anak kelas 1 SD di Humbang Hasundutan dengan percaya diri menjelaskan konsep perkalian. Bagi saya, ini adalah hal yang luar biasa! Anak-anak ini tidak hanya mengingat materi dengan baik, tetapi mereka juga mampu menyampaikannya dengan jelas. Kepercayaan diri yang mereka tunjukkan adalah modal dasar untuk masa depan mereka. Indonesia adalah negara kaya dengan sumber daya alam dan manusia. Namun, sering kali kita menghadapi kekurangan orang-orang yang menggunakan akal sehat dan hati yang tulus dalam menjalankan tanggung jawab mereka. Di sinilah peran pendidikan sangat penting. Jika saya mengibaratkan pendidikan sebagai anggota tubuh, maka pendidikan adalah otak dan hati sebuah negara. Ia berfungsi seperti otak yang mengembangkan kecerdasan dan inovasi untuk kemajuan teknologi, ekonomi, dan stabilitas politik, sekaligus membentuk karakter, empati, dan nilai-nilai moral yang dibutuhkan untuk menciptakan masyarakat yang damai, adil, dan berperikemanusiaan. Keseimbangan antara kecerdasan (otak) dan hati (moral dan empati) akan menciptakan negara yang kuat, berdaya saing, dan tetap peduli terhadap kesejahteraan sosial. Melihat peluang ini, saya merasa terinspirasi untuk berkontribusi dalam dunia pendidikan di Indonesia. Dengan kepercayaan dan kesempatan yang diberikan oleh Prof. Yohanes Surya di Kabupaten Bangli, semangat saya semakin berkobar untuk menjadi guru yang mengedepankan hati dan akal. Saat melakukan diagnostik awal, saya menemukan banyak anak yang masih kesulitan dalam berhitung dan harus menggunakan alat bantu seperti kertas untuk menyelesaikan soal. Namun, setelah pelatihan menggunakan');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Mai Rosalli Matondang S.Pd.K', '/assets/images/trainers/default.png', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Humbang Hasundutan yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Mai Rosalli Matondang S.Pd.K dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Mai Rosalli Matondang S.Pd.K membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Humbang Hasundutan', 'Sumatera Utara', 150000000.0, 0.0, 0, '1234', 'Sebagai guru dengan latar belakang pendidikan Kristen, saya melihat Metode GASING sebagai wujud nyata pelayanan kasih melalui pendidikan. Mengajar dengan hati dan kesabaran tanpa batas di Humbang Hasundutan membawa damai dan keceriaan di ruang kelas. Anak-anak tidak hanya berkembang secara kognitif melalui numerasi cepat, tetapi juga tumbuh menjadi pribadi yang berani, disiplin, dan menghargai sesama.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Makdar Anwar S.Pd.', '/assets/images/trainers/trainer_45.jpg', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Pulau Morotai yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Makdar Anwar S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Makdar Anwar S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Pulau Morotai', 'Indonesia', 150000000.0, 0.0, 0, '1234', 'Metode GASING adalah sebuah metode pembelajaran matematika yang dikembangkan oleh Prof. Yohanes Surya. Metode ini telah membawa perubahan besar dalam cara saya memandang pelajaran ini dan tak diragukan lagi mengubah wajah pendidikan di Indonesia. GASING bukan hanya sebuah pendekatan baru, tetapi juga revolusi dalam belajar, terutama bagi mereka yang merasa matematika adalah pelajaran yang sulit dan ditakuti. Sebagai seorang guru matematika, saya dulunya sangat kaku. Bahkan untuk melakukan aktivitas di dalam kelas, saya hanya bisa berdiri tegak seperti biasa. Hal ini membuat pembelajaran matematika terasa membosankan, sehingga jumlah siswa yang hadir di kelas selalu minim. Mengganti metode dan suasana kelas saja tidak cukup untuk membuat matematika menjadi pelajaran yang disukai. Dalam kegalauan itu, Metode GASING (Gampang, Asik, dan Menyenangkan) datang menyapa. Metode GASING menghadirkan pembelajaran matematika yang mudah, menyenangkan, dan penuh aktivitas menarik. Materi pembelajaran dikemas dalam bentuk yang sederhana dan diajarkan dengan cara yang menyenangkan, sehingga GASING sangat membantu menghilangkan kecemasan dan ketakutan terhadap matematika. GASING telah merubah saya—pola pikir saya, cara mengajar saya, dan cara berinteraksi saya. Saya merasa menjadi pribadi yang baru, lebih bebas, dan lebih menyenangkan. GASING tidak hanya mengembangkan kemampuan berpikir, tetapi juga mengajarkan kita untuk selalu mengajar dengan hati (compassion). Metode ini membuat saya bisa tertawa dan bergembira ketika mengajarkan matematika. Tertawa karena matematika menjadi pelajaran yang mudah dan tidak menakutkan lagi, serta bergembira melihat siswa belajar matematika dengan penuh senyuman dan kegembiraan. GASING bukan hanya merubah diri saya, tetapi juga merubah wajah pendidikan di Indonesia. Saya percaya bahwa mengenalkan dan menyebarluaskan Metode GASING adalah langkah penting dalam memajukan pendidikan di Indonesia.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Manggih Bumi Bagus S.Pd.', '/assets/images/trainers/trainer_46.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Banyuwangi yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Manggih Bumi Bagus S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Manggih Bumi Bagus S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Banyuwangi', 'Jawa Timur', 150000000.0, 0.0, 0, '1234', 'Saya seorang guru sejak tahun 2008. Bisa disebut saya sudah menjadi guru selama 16 tahun. Disana banyak sekali pengalaman yang saya dapatkan. Sebelumnya perkenalkan, nama saya Manggih Bumi Bagus, saya berasal dari Kabupaten Banyuwangi, Jawa Timur. Sebuah kabupaten paling ujung di Pulau Jawa yang biasa disebut dengan Sunrise of Java. Bagi saya, guru merupakan sebuah profesi yang sangat mulia. Karena guru memiliki cita-cita membentuk dan mencetak generasi penerus bangsa. Dengan menjadi guru ini pun, saya merasakan banyak sekali hal yang menarik dalam hidup. Namun pengalaman saya yang sangat luar biasa adalah ketika saya mengenal GASING. Pada awalnya, saya penasaran dengan pelatihan GASING yang ada di daerah saya. Saya pikir pelatihan tersebut hanya untuk guru matematika saja. Namun ketika saya mendapatkan kesempatan untuk menjadi peserta pelatihan, disanalah saya mulai merasakan dampak GASING terhadap diri saya. Banyak sekali yang saya dapatkan ketika saya mengenal pembelajaran dengan Metode GASING. Apa yang saya dapatkan saat pelatihan GASING tidak hanya saya implementasikan pada matematika, namun bisa saya implementasikan terhadap pelajaran yang lain. Dengan Metode GASING ini terbukti mampu membuat siswa untuk lebih cakap dalam berhitung, siswa menjadi lebih senang dalam belajar matematika. Tidak lagi mereka takut terhadap matematika. GASING juga telah banyak mengubah gaya pembelajaran saya. Saya yang awalnya seorang guru killer, berubah menjadi guru yang sangat menyenangkan dan selalu dirindukan oleh anak-anak. Mengubah saya menjadi guru yang selalu memiliki cara tersendiri untuk mengajar dan membuat anak-anak senang. Membuat saya memiliki banyak sekali permainan yang saya gabungkan dengan kegiatan pembelajaran.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Mario Capestrano Gesiradja S.Pd.,Gr.', '/assets/images/trainers/default.png', 'S2 Pendidikan Masyarakat', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Ende yang sedang menempuh program studi S2 Pendidikan Masyarakat Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Mario Capestrano Gesiradja S.Pd.,Gr. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Mario Capestrano Gesiradja S.Pd.,Gr. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Ende', 'Indonesia', 150000000.0, 0.0, 0, '1234', 'Pengabdian sebagai guru garis depan mengajarkan saya bahwa tantangan terbesar adalah memotivasi siswa. Metode GASING terbukti menjadi solusi mutakhir. Dengan permainan interaktif dan lagu matematika yang riang, anak-anak di pelosok Kupang belajar tanpa merasa dipaksa. Perubahan antusiasme belajar numerasi ini memberikan harapan baru bagi masa depan kemandirian daerah kami.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Marni Sari S.Pd., Gr.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Muaro Jambi yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Marni Sari S.Pd., Gr. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Marni Sari S.Pd., Gr. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Muaro Jambi', 'Indonesia', 150000000.0, 0.0, 0, '1234', 'Mengajar matematika dengan Metode GASING memberikan kepuasan yang luar biasa. Melalui pelatihan yang intensif bersama tim Profesor Yohanes Surya, saya belajar bagaimana membedah matematika rumit menjadi konsep yang sangat sederhana. Penerapan metode ini di daerah 3T telah membuktikan bahwa keterbatasan fasilitas fisik bukanlah penghalang untuk mencetak anak-anak yang cerdas numerasi.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Meki Atmaja S.Pd.SD', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bangka Tengah yang sedang menempuh program studi S2 Pendidikan Guru Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Meki Atmaja S.Pd.SD dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Meki Atmaja S.Pd.SD membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bangka Tengah', 'Kepulauan Bangka Belitung', 150000000.0, 0.0, 0, '1234', 'Sebagai pendidik SD di Bangka Barat, saya melihat Metode GASING memberikan dampak transformatif pada kemampuan dasar berhitung anak-anak. Metode ini sangat mudah diterima karena menggunakan media konkret yang ada di sekitar siswa. Anak-anak menjadi sangat antusias, kreatif, dan saling mendukung saat menyelesaikan latihan mencongak bersama. Ini adalah kunci kecerdasan masa depan bangsa.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Melisa S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Batang Hari yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Melisa S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Melisa S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Batang Hari', 'Indonesia', 150000000.0, 0.0, 0, '1234', 'Matematika GASING mengubah pola pikir saya tentang cara mengajar yang efektif. Di bawah bimbingan langsung para mentor berpengalaman, saya belajar bahwa matematika harus diajarkan dengan senyuman dan permainan. Ketika anak-anak didik saya di Sumatera Barat mulai menanti-nantikan jam pelajaran matematika dengan gembira, saya tahu GASING telah berhasil menanamkan kecintaan belajar pada diri mereka.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Mespin Zulian Samaloisa S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Kepulauan Mentawai yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Mespin Zulian Samaloisa S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Mespin Zulian Samaloisa S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Kepulauan Mentawai', 'Sumatera Barat', 150000000.0, 0.0, 0, '1234', 'Masyarakat Mentawai membutuhkan lompatan kualitas numerasi agar dapat bersaing di era modern. Metode GASING terbukti mampu mewujudkan hal tersebut secara instan. Saya melihat anak-anak kepulauan yang semula terasing dari matematika kini mampu menghitung dan berlogika dengan sangat cepat di luar kepala. Dedikasi Prof. Yohanes Surya menginspirasi saya untuk terus melayani di pelosok Nusantara.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Nafsia Lestarya Purba S.Pd.', '/assets/images/trainers/trainer_52.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Humbang Hasundutan yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Nafsia Lestarya Purba S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Nafsia Lestarya Purba S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Humbang Hasundutan', 'Sumatera Utara', 150000000.0, 0.0, 0, '1234', 'Metode GASING telah memperlengkapi saya dengan keterampilan mengajar yang luar biasa di Simalungun. Dengan mengajarkan matematika secara asyik dan visual, pemahaman anak-anak meningkat pesat. Proses mencongak cepat melatih konsentrasi dan ketangkasan mental mereka. GASING benar-benar mengubah atmosfer kelas saya dari ketegangan menjadi penuh canda tawa dan prestasi.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Ni Ketut Yeni Priskila S.S, M.Pd.', '/assets/images/trainers/default.png', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Parigi Moutong yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Ni Ketut Yeni Priskila S.S, M.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Ni Ketut Yeni Priskila S.S, M.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Parigi Moutong', 'Sulawesi Tengah', 150000000.0, 0.0, 0, '1234', 'Ini adalah kisah perjalananku, mulai dari awal berkenalan dengan GASING hingga jatuh cinta mati pada metode ini. Semua berawal dari perintah Ibu Kepala Disdikbud Kabupaten Parigi Moutong kepada saya untuk mengikuti pelatihan GASING di kota Tinombo, Parigi Moutong. Awalnya, semuanya terasa aneh dan tidak jelas karena saya masih asing dengan istilah GASING, terlebih lagi ini adalah pelatihan matematika yang berhubungan dengan numerasi. Sebagai guru Bahasa Inggris, timbul pertanyaan dalam benakku, "Apa tidak salah tunjuk?" dan "Apakah saya bisa mengikuti pelatihan ini?" Mendengar kata "matematika" saja sudah membuat kepalaku berdenyut. Namun, Ibu Kadis meyakinkan saya bahwa saya pasti bisa. Berbekal keyakinan ini, saya nekat mengikuti pelatihan GASING untuk pertama kalinya sebagai peserta. Ini adalah pelatihan tergila yang pernah saya ikuti. Selain sangat disiplin dalam waktu, pelatihan GASING penuh dengan lagu, tarian, tawa, permainan, kerjasama tim, kemandirian, serta cara mengajar yang atraktif. Semua ini mampu memporak-porandakan kesan matematika yang ‘seram'' dan pelatihan yang ‘membosankan''. Pelatihan yang berlangsung selama 15 hari, dari pukul 07.30 hingga 17.00, tidak membuatku menyerah; sebaliknya, aku merasa lebih sehat dan bahagia. Jika pelatihan pada umumnya banyak duduk dan mendengarkan, pelatihan GASING justru banyak berdiri, bergoyang, praktik mengajar dengan kreativitas, dan tetap fokus dalam kebisingan. Setelah menjadi peserta dari 17 September hingga 4 Oktober 2023, saya terpilih menjadi salah satu trainer GASING pada 25 Oktober 2023. Inilah titik balik saya dari guru yang biasa-biasa saja menjadi guru yang heboh dan kreatif. Setiap kali mengimbas ke daerah, saya sangat antusias, bersemangat, dan penasaran tantangan apa lagi yang akan saya hadapi di lapangan nanti, karena setiap daerah memiliki karakter dan kebudayaan yang berbeda. Namun, pada kenyataannya, tidak ada yang perlu dikhawatirkan karena GASING telah membentuk karakter Ni Ketut Yeni Priskila, S.S., M.Pd - Trainer Parigi Moutong GASING Mengubahku dan Pendidikan Indonesia Menjadi Lebih Baik');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Ninik Wijiningsih M.Pd.', '/assets/images/trainers/trainer_54.jpg', 'S2 Pengembangan Kurikulum', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bojonegoro yang sedang menempuh program studi S2 Pengembangan Kurikulum Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Ninik Wijiningsih M.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Ninik Wijiningsih M.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bojonegoro', 'Indonesia', 150000000.0, 0.0, 0, '1234', 'Langkah kecilku berawal dari menjadi peserta Pelatihan GASING Tahap I di Kabupaten Bojonegoro. Awalnya saya tidak menyangka, bahwa pelatihan GASING Tahap I di Bojonegoro saya diberikan kesempatan ikut menjadi peserta. Bagi saya istilah "GASING" itu asing, kemudian saya search sehingga sekilas tahu bahwa GASING itu adalah sebuah metode belajar matematika dari Prof. Yohanes Surya, Ph.D. Saat pelatihan, trainer-trainer GASING membuat saya terpana karena heboh, energik, tidak ada rasa lelah dan mengajar sepenuh hati. Kehebohan dan energik para trainer itu ternyata menular, semua peserta heboh seperti mendapat suntikan virus-virus heboh. Tidak ada satu pun peserta yang mengantuk, seperti pelatihan-pelatihan yang pernah saya ikuti sebelumnya. Selanjutnya saya mengimplementasikan Metode GASING ini di sekolah dan mengimbaskan ke semua guru di kecamatan masing-masing. Kesempatan diberikan GASING kepada saya dengan diikutsertakan dalam kegiatan Numerasi Asyik Nasional (Nuansa 2) di Bogor, Pelatihan Madrasah Pandai Berhitung di Balai Diklat Kemenag Surabaya yang diikuti guru pilihan dari masing-masing provinsi seluruh Indonesia, Numerasi Asyik Nasional dengan materi Pecahan dan Desimal di Sentani Jayapura, 108 Guru Inspiratif Nasional GASING 2024. Sungguh luar biasa, banyak hal yang saya dapat dari GASING yang mungkin sebelumnya tidak pernah terbayangkan. GASING mengubah mindset saya bahwa matematika itu SULIT karena rumus dan hafalan menjadi konsep matematika yang gampang, mudah dipahami dengan cara mengajarkan konkret, abstrak, mencongak. GASING memvisualisasi konsep matematika secara konkret/kontekstual sesuai dengan tahap perkembangan anak, menggunakan logika sederhana, game/permainan, lagu, alat peraga serta cara-cara kreatif, asyik, dan menyenangkan dalam pembelajaran. Metode GASING dengan mengintegrasikan konsep 8C yang sering digunakan dalam dunia pendidikan abad ke-21, bisa menjadi pendekatan yang kuat dalam transformasi pembelajaran.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Novie Anggela S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Gunung Mas yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Novie Anggela S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Novie Anggela S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Gunung Mas', 'Kalimantan Tengah', 150000000.0, 0.0, 0, '1234', 'Menjadi bagian dari tim pengimbasan GASING mengajarkan saya arti penting dari kolaborasi dan kerja keras demi masa depan anak-anak di Kalimantan Barat. Metode ini tidak hanya meningkatkan kompetensi matematika siswa, tetapi juga menumbuhkan rasa percaya diri mereka secara luar biasa. Saya merasa terhormat bisa berkontribusi menyalakan pelita numerasi di daerah-daerah terpencil Indonesia.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Novita Konnianty Lassi S.Pd, MM.', '/assets/images/trainers/default.png', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Kupang yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Novita Konnianty Lassi S.Pd, MM. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Novita Konnianty Lassi S.Pd, MM. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Kupang', 'Nusa Tenggara Timur', 150000000.0, 0.0, 0, '1234', 'Sebagai guru dengan wawasan manajemen, saya melihat Metode GASING sebagai sistem pengajaran numerasi yang sangat efisien dan terstandarisasi dengan baik. Penerapan metode ini di NTT terbukti mempercepat penguasaan matematika dasar anak-anak hingga beberapa kali lipat. Suasana belajar yang gembira dan interaktif sangat mendukung perkembangan karakter kepemimpinan dan kemandirian mereka.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Ocevina Dimor M.Pd.', '/assets/images/trainers/trainer_57.jpg', 'S2 Pengembangan Kurikulum', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Jayapura yang sedang menempuh program studi S2 Pengembangan Kurikulum Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Ocevina Dimor M.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Ocevina Dimor M.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Jayapura', 'Papua', 150000000.0, 0.0, 0, '1234', 'Perkenalkan, nama saya Ocevina Dimor, AT, asal kota Jayapura. Saat ini, saya aktif mengajar di kelas 5 SD, tepatnya di SDN 1 Abepura, kota Jayapura, Provinsi Papua. Merupakan sebuah kehormatan dan kebanggaan bagi saya menjadi bagian dari tim Trainer Gasing Academy Indonesia di bawah naungan Profesor Yohanes Surya. Bagi saya, beliau adalah sosok malaikat tak bersayap bagi dunia pendidikan di Indonesia. Saya ingin berbagi sedikit cerita tentang bagaimana karakter saya sebagai seorang guru yang pemalu dan tidak percaya diri dalam mengajarkan matematika berubah drastis setelah menjadi peserta dan trainer dalam pengimbasan nasional di beberapa daerah di Indonesia, serta dalam kegiatan Numerasi Asyik Nasional (NAN). Dengan memahami tahapan dan konsep BaKalKuBagi dan PeDe, saya semakin memahami, menguasai, dan berkreasi dalam setiap aktivitas pembelajaran di kelas saya. Selain itu, saya juga berkesempatan menjadi fasilitator dalam aktivitas kombel di sekolah kami dan diberikan kepercayaan menjadi pengajar dan pembimbing bagi siswa kelas 5 yang akan mengikuti ANBK (Asesmen Nasional Berbasis Komputer). Tidak hanya itu, saya juga diminta oleh salah satu kepala sekolah SD di kota Jayapura untuk mengimbaskan materi BaKalKuBagi di sekolahnya. Semua pengalaman ini saya peroleh setelah mengenal Metode GASING. Dari semua pengalaman ini, perubahan terbesar dalam diri saya adalah saya menjadi seorang guru yang sangat mencintai matematika dan selalu mengajar dengan hati. Tidak ada lagi guru yang monoton, tidak ada lagi guru yang pemalu dan tidak percaya diri. Betapa luar biasanya Metode GASING telah mengubah diri saya menjadi seorang guru yang inspiratif bagi sekolah tempat saya mengajar, bagi kota Jayapura, bagi Papua, dan bagi Indonesia. Sebuah kebanggaan bagi kami di Papua bahwa GASING telah merubah pandangan tentang SDM generasi emas berkualitas di tanah Papua. Anak-anak pedalaman Papua yang dianggap');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Ofir Nokas S.Th, Gr.', '/assets/images/trainers/default.png', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Lanny Jaya yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Ofir Nokas S.Th, Gr. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Ofir Nokas S.Th, Gr. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Lanny Jaya', 'Papua Pegunungan', 150000000.0, 0.0, 0, '1234', 'Mengajar teologi dan numerasi di Timor Tengah Selatan memberikan pengalaman spiritual yang mendalam bagi saya. Dengan Metode GASING, saya menyaksikan transformasi karakter anak-anak: dari pemalu dan minder menjadi pribadi yang berani tampil, cerdas berpikir logis, dan penuh optimisme. GASING membuktikan bahwa pendidikan dengan hati mampu melahirkan perubahan besar di pelosok tanah air.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Oktofianus Sedubun S.Pd.', '/assets/images/trainers/default.png', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Ambon yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Oktofianus Sedubun S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Oktofianus Sedubun S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Ambon', 'Maluku', 150000000.0, 0.0, 0, '1234', 'Tantangan numerasi di Maluku Tenggara membutuhkan pendekatan pengajaran yang segar dan berpihak pada anak. Metode GASING hadir memberikan solusi konkret dengan mengubah matematika menjadi sebuah petualangan belajar yang seru. Ketika melihat anak-anak pesisir berteriak gembira saat berhasil mencongak perkalian cepat, saya merasakan kebahagiaan sejati sebagai seorang pendidik.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Petrus Kanisius Nama Doni S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Lembata yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Petrus Kanisius Nama Doni S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Petrus Kanisius Nama Doni S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Lembata', 'Nusa Tenggara Timur', 150000000.0, 0.0, 0, '1234', 'Sebagai putra daerah Flores Timur, saya bercita-cita membawa perubahan mutu pendidikan matematika bagi anak-anak saya. Metode GASING mewujudkan mimpi itu dengan sangat indah. Metode ini menyederhanakan perhitungan rumit menjadi permainan edukatif yang menyenangkan. Anak-anak kini memiliki motivasi belajar yang tinggi dan tidak lagi menganggap sekolah sebagai beban.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Puspita Baity S.Pd.', '/assets/images/trainers/trainer_61.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Tulang Bawang Barat yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Puspita Baity S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Puspita Baity S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Tulang Bawang Barat', 'Indonesia', 150000000.0, 0.0, 0, '1234', 'Hai semuanya, salam hangat bagi para pembaca! Saya ingin sedikit bercerita tentang bagaimana GASING mengubah pribadi saya serta anak-anak di Indonesia, dan memberikan pengaruh yang luar biasa. Pertama-tama, saya ingin mengucapkan terima kasih kepada GASING, khususnya kepada Prof. Yohanes Surya, yang telah menciptakan metode belajar yang asyik, gampang, dan menyenangkan. Merupakan kebanggaan bagi saya bisa menjadi bagian dari trainer GASING yang menyebarkan cinta dan kasih kepada anak- anak, serta dapat mengunjungi daerah-daerah di Indonesia yang sebelumnya tidak pernah terpikirkan untuk saya. Awal mula saya mengenal Metode GASING adalah pada tahun 2023, tepatnya di bulan Oktober. Saya diberikan amanah oleh Bapak Kepala Sekolah untuk mengikuti pelatihan GASING selama 15 hari. Awalnya, saya merasa bingung tentang metode ini, terutama ketika belajar tentang bilangan yang sudah saya kenal. Namun, hari demi hari, saya menemukan metode ini sangat menyenangkan dan luar biasa. Antusiasme saya meningkat, dan saya semangat mengikuti pelatihan. Pengalaman pertama saya sebagai trainer di Aceh Timur juga sangat luar biasa. Saat mengajar, respon anak-anak sangat energik, mereka berlari kesana kemari dan melompat-lompat, sama seperti yang saya rasakan dulu. Namun, seiring berjalannya waktu, mereka menjadi sangat antusias dan tidak ingin pelatihan berakhir. Pada pelatihan kedua di Badung, setelah selesai, anak-anak tidak mau berpisah. Ketika saya bertanya mengapa, mereka menjawab, "Ibu baik, ga pernah marah-marah, beda sama guru kita." Kata-kata itu sangat menyentuh bagi saya. Pernyataan tersebut membuat saya merenung dan sedikit kaget dengan perubahan pada diri saya. Selama ini, saya dikenal sebagai guru yang galak, jarang senyum, dan sering marah ketika anak- anak berlari saat belajar. Namun, setelah mengenal GASING, semuanya berubah. Satu hal yang selalu saya ingat dari Prof. adalah pentingnya mengajar dengan hati.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Rabudin S.Pd.', '/assets/images/trainers/trainer_62.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Singkawang yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Rabudin S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Rabudin S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Singkawang', 'Indonesia', 150000000.0, 0.0, 0, '1234', 'Sebagai seorang guru, saya seringkali kesulitan dalam mengajarkan matematika kepada murid di kelas. Hal ini disebabkan oleh anggapan murid bahwa matematika adalah pelajaran yang sangat menakutkan. Angka-angka, bilangan, simbol, dan rumus-rumus yang begitu banyak membuat mereka malas dan tidak senang belajar matematika. Apalagi, matematika sering diajarkan dengan metode yang kurang tepat, sehingga baik guru maupun murid kehilangan semangat dalam pembelajaran. Namun, semuanya berubah ketika saya diperkenalkan dengan Metode GASING. Metode GASING, yang merupakan singkatan dari Gampang, Asyik, dan Menyenangkan, digagas oleh Prof. Yohanes Surya, Ph.D., dan telah membawa banyak perubahan bagi saya, baik dalam cara belajar maupun mengajar. Saya bersyukur dan berterima kasih kepada Bapak Prof. Yohanes Surya dan Gasing Academy yang telah memberikan kesempatan kepada saya untuk menjadi Trainer dan belajar banyak tentang metode ini. GASING membawa secercah harapan bagi saya untuk menjadi guru yang lebih baik. Awalnya, tidak mudah untuk mengubah kebiasaan mengajar saya. Murid-murid juga sempat bingung dengan metode baru ini. Namun, seiring berjalannya waktu, mereka mulai terbiasa dan bahkan menyukai pelajaran matematika. Mereka aktif berpartisipasi dalam kegiatan belajar, saling membantu, dan tidak lagi takut menghadapi soal-soal yang sulit. Metode GASING telah mengubah cara saya dan anak-anak memandang matematika. Matematika bukan lagi sekadar kumpulan rumus yang harus dihafal, tetapi sebuah ilmu yang menyenangkan dan penuh tantangan. Saya menjadi lebih kreatif dalam merancang kegiatan pembelajaran dan lebih sabar dalam membimbing murid. Saya merasa terpanggil untuk berbagi pengalaman dengan guru-guru lain. Saya aktif mengikuti pelatihan yang diadakan oleh Gasing Academy dan memberikan pelatihan kepada rekan-rekan guru di sekolah. Saya berharap Metode GASING dapat diterapkan di');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Rani Tartillah S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Musi Banyuasin yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Rani Tartillah S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Rani Tartillah S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Musi Banyuasin', 'Sumatera Selatan', 150000000.0, 0.0, 0, '1234', 'Pelatihan Metode GASING mengajarkan saya bahwa kunci keberhasilan belajar adalah menciptakan emosi positif di dalam kelas. Dengan bernyanyi dan mencongak bersama, anak-anak di pelosok Riau merasa dihargai dan dicintai. Perkembangan kemampuan matematika dasar mereka yang sangat pesat membuktikan efektivitas metode yang luar biasa ini bagi pemerataan kualitas pendidikan nasional.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Rita S.Pd.', '/assets/images/trainers/trainer_64.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Gunung Mas yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Rita S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Rita S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Gunung Mas', 'Kalimantan Tengah', 150000000.0, 0.0, 0, '1234', 'Hal pertama yang ingin saya sampaikan kepada Prof. Yohanes Surya dan tim hebatnya adalah luar biasa dan terima kasih. Saya sangat bersyukur dan bangga bisa bergabung dengan orang-orang hebat, hangat, supel, dan luar biasa di Gasing Academy. GASING tidak hanya memberikan metode dan ilmu pengetahuan saat pengimbasan, tetapi juga membawa harapan baru bagi semua peserta. Hal ini terbukti saat pengimbasan pertama saya di Lanny Jaya, Papua Pegunungan, di mana saya dipercaya membimbing siswa SMP. Dalam pikiran saya, mengajar anak-anak SMP pasti tidak sulit. Namun, saya terharu saat menemukan salah satu murid saya di kelas VIII yang belum lancar membaca dan menulis, serta mengalami kesulitan dalam berbahasa Indonesia. Hal ini membuatnya merasa malu dan tidak percaya diri. Meskipun sempat pesimis, semangat dan kegigihannya untuk berjalan kaki selama 1-2 jam setiap hari demi mengikuti kegiatan GASING memotivasi saya.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Rita Yuana S.Pd.SD', '/assets/images/trainers/trainer_65.jpg', 'S2 Pendidikan Masyarakat', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Bojonegoro yang sedang menempuh program studi S2 Pendidikan Masyarakat Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Rita Yuana S.Pd.SD dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Rita Yuana S.Pd.SD membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Bojonegoro', 'Indonesia', 150000000.0, 0.0, 0, '1234', 'Perubahan besar selalu diawali dari hal-hal kecil. GASING merubah mindset para guru dalam mengajarkan matematika yang awalnya terkesan sukar, menakutkan dan bikin bosan peserta didik menjadi lebih gampang, asyik dan menyenangkan. Jika cara berfikir guru sudah berubah menjadi lebih positif, maka akan berdampak positif pula ke peserta didik. Proses perubahan ini tentu tidak mudah, tapi GASING telah membuktikan pada kita semua. Pendidikan adalah proses memanusiakan manusia yang bertujuan untuk mengembangkan potensi peserta didik sebagai manusia seutuhnya. GASING hadir dengan keterampilan mengajar dengan hati dimana guru mengajar dengan maksimal dan menggali potensi peserta didik secara optimal. GASING membuat kami menjadi guru yang dirindukan peserta didik. Guru yang enerjik, aktif, mengajak murid menyanyi dan menari sehingga belajar menjadi asyik dan menyenangkan. Perjalanan yang harus kami tempuh sebagai trainer GASING memberikan pengalaman seru sekaligus haru yang tidak akan pernah kami lupakan. Para guru dan murid yang begitu semangat mengikuti pelatihan GASING adalah motivasi bagi kami dalam berbagi ilmu dan berkolaborasi. Pelatihan yang diawali jam 08.00 sampai 17.00 selama 15 hari tidak membuat peserta lelah. Bahkan ingin menambah. Ini adalah bukti nyata bahwa GASING membuat kita semua menjadi senang belajar. Inilah GASING yang telah menjadi lilin penerang menuju Indonesia emas 2045. Bukan hanya teori, tapi sudah memberikan bukti. Saatnya sekarang kita rapatkan barisan dan bergandengan tangan untuk menjadi agen perubahan dalam dunia pendidikan. Kalo bukan kita siapa lagi. Kalo tidak sekarang kapan lagi. Bersama GASING, Indonesia bisa….');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Rivaldo Apriando Waas S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Umum dan Karakter', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Ambon yang sedang menempuh program studi S2 Pendidikan Umum dan Karakter Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Rivaldo Apriando Waas S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Rivaldo Apriando Waas S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Ambon', 'Maluku', 150000000.0, 0.0, 0, '1234', 'Pendidikan di Maluku membutuhkan dorongan numerasi yang masif agar setara dengan daerah lainnya. Melalui Metode GASING, saya dilatih langsung untuk membimbing anak-anak pedalaman mencongak cepat tanpa alat bantu kalkulator. Menyaksikan ketangkasan berpikir mereka berkembang dalam waktu singkat telah mengukuhkan keyakinan saya bahwa Indonesia Timur memiliki masa depan emas.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Rr. Selvi Amelia Rahmawati. S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Biak Numfor yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Rr. Selvi Amelia Rahmawati. S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Rr. Selvi Amelia Rahmawati. S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Biak Numfor', 'Papua', 150000000.0, 0.0, 0, '1234', 'Membawa Metode GASING ke dalam kelas sekolah dasar di Jawa Tengah telah melahirkan perubahan suasana belajar yang luar biasa kreatif. Anak-anak menikmati setiap sesi penjumlahan dan perkalian melalui kuis interaktif dan koreografi gerakan matematika yang dinamis. GASING membentuk karakter guru yang sabar, inovatif, dan selalu mengajar dengan hati yang tulus.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Safiru Hunas S.Pd.', '/assets/images/trainers/trainer_68.jpg', 'S2 Pendidikan Guru', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Buton yang sedang menempuh program studi S2 Pendidikan Guru Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Safiru Hunas S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Safiru Hunas S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Buton', 'Sulawesi Tenggara', 150000000.0, 0.0, 0, '1234', 'Pertama-tama saya bersyukur kepada Tuhan Yang Maha Esa karena berkat karunia-Nya sehingga saya bisa merasakan nikmat yang begitu luar biasa. Terima kasih juga kepada Prof Yohanes Surya, P.hD yang telah menciptakan metode pembelajaran yang begitu fenomenal yang dikenal dengan sebutan "GASING": Gampang, Asyik, dan Menyenangkan. Saya bercerita sedikit tentang awal mula ketika saya akhirnya bisa mengenal Metode GASING ini, ketika di daerah saya yaitu Kabupaten Buton bekerja sama dengan Yayasan Teknologi Indonesia Jaya mengadakan pengimbasan nasional dari tanggal 8 sampai 24 Juni 2023. Disinilah saya bertemu dengan guru-guru hebat para AT dari berbagai daerah di Indonesia, dari mereka saya belajar matematika dengan cara yang lain dari biasanya, belajar matematika begitu gampang, asyik dan menyenangkan karena suasana kelas yang gaduh dan bising, tetapi siswa bisa menerima materi dengan baik karena mereka dalam keadaan senang dan gembira. Saya sangat bersyukur sekali bisa bergabung dengan guru- guru hebat di seluruh Indonesia, dimana saya dipercaya untuk menjadi AT pada pengimbasan nasional. Awal pengimbasan saya dimulai dari ujung timur Indonesia yaitu di Papua Barat tepatnya di Kabupaten Manokwari Selatan, banyak sekali pengalaman yang saya dapat di sana terutama saya bisa melihat bagaimana keadaan pendidikan di sana. Dari sinilah awalnya sehingga saya bisa melihat daerah-daerah lain di Indonesia mulai dari Jakarta, Sulawesi Tengah, Maluku, Banten, Bandung, dan terakhir ini dipercaya untuk mengimbas di Papua Tengah Kabupaten Intan Jaya. Semoga saya masih diberi kepercayaan berikutnya oleh Prof. Yohanes Surya, dan saya mendoakan semoga Prof Yaohanes Surya selalu diberi kesehatan agar terus menebar benih-benih kebaikan demi masa depan anak-anak Indonesia.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Sirwan S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Buton Selatan yang sedang menempuh program studi S2 Pendidikan Guru Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Sirwan S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Sirwan S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Buton Selatan', 'Sulawesi Tenggara', 150000000.0, 0.0, 0, '1234', 'Contents Teristimewa Untukmu, Prof. Susana Putriani Saranaro Selamat Ulang Tahun, Prof. Tazkiyah Nurul Hidayah Mointi,S.Pd Pelangi Impian Wa Ariana, S.Pd Gasing Gave me a Chance to Change and the Chance to Change Others Witnny Stesia Warouw Kehebatan Gasing Yoani Mbipi Kisah Gasing dan Ucapan Birthday Pak Prof. ❤ Yogina Pratiwi Profesor Sang Pejuan Pendidikan Atty Marta Kambu Gasing Mengubah Caraku Mengajar Betti Fransiska Samosir Pengalaman Mengajar Gasing Darlin Adam, S.Pd Kesempatan Emas Greiswati Tahulending 196 Kasih Hilda Naomi Bernedit Paima Uli Siregar 200 Nikmati Proses di Setiap Tempat Ima AP, S.Pd Gasing dan Papua');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Tari Marselia S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal DKI Jakarta yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Tari Marselia S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Tari Marselia S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'DKI Jakarta', 'DKI Jakarta', 150000000.0, 0.0, 0, '1234', 'Metode GASING telah memperbarui komitmen keguruan saya untuk melayani anak-anak di Kepulauan Bangka Belitung. Pengalaman mengajarkan mencongak cepat lewat lagu pasangan sepuluh membuat anak-anak sangat mencintai pelajaran matematika. Saya sangat bersyukur bisa menguasai metode ini untuk mempersiapkan generasi muda daerah saya yang cerdas numerasi dan berkarakter mulia.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Tionomi Sihite S.Pd.', '/assets/images/trainers/trainer_71.jpg', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Humbang Hasundutan yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Tionomi Sihite S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Tionomi Sihite S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Humbang Hasundutan', 'Sumatera Utara', 150000000.0, 0.0, 0, '1234', 'Saya masih ingat saat pertama kali mengenal Metode GASING. Waktu itu saya ditugaskan kepala sekolah untuk mengikuti pelatihan matematika dengan Metode GASING. Awalnya saya berpikir, pelatihannya akan membosankan dan hanya akan mengajarkan cara cepat berhitung matematika. Tetapi di hari pertama pelatihan, Prof. Yohanes Surya mengajarkan Matematika dengan cara yang sangat gampang, asyik, dan menyenangkan. Kegiatan selama pelatihan menjadi sangat seru dan interaktif. Salah satu yang tidak pernah saya dapatkan selama pembelajaran matematika, dalam Metode GASING menggunakan permainan dan lagu dalam belajar. Banyak sekali permainan yang berhubungan dengan materi pembelajaran. Dan banyak lagu yang diajarkan untuk membantu memahami materi dan berlatih soal melalui lagu tanya jawab. Pembelajaran matematika layaknya seperti konser pada saat itu tetapi sambil belajar. Cara ini mengubah pola pikir saya bahwa pembelajaran matematika bukan lagi pembelajaran yang hening melainkan pembelajaran dengan suasana yang gaduh dan bising. Hari demi hari saya lalui dan tidak terasa melelahkan walau pelatihan berlangsung dari pagi sampai sore hari. Saya asyik dan tidak ingin berhenti mengerjakan setiap soal-soal yang diberikan. Alhasil saya lebih cepat dan pandai berhitung matematika. Setelah mengikuti GASING, saya menjadi sangat antusias ingin menerapkan metode ini di sekolah saya dan ternyata anak begitu bahagia dalam belajar matematika dan mereka menjadi lebih cepat berhitung. Melalui metode ini juga membantu saya untuk meningkatkan kepercayaan diri dan benar-benar mengubah pribadi saya. Saya awalnya adalah seorang guru yang mempunyai kepribadian introvert dan tidak percaya diri dan selalu takut berinteraksi dengan orang-');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Titin Usmar S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Buton yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Titin Usmar S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Titin Usmar S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Buton', 'Sulawesi Tenggara', 150000000.0, 0.0, 0, '1234', 'Sebagai guru di pelosok Lombok Utara, Nusa Tenggara Barat, saya menyaksikan bagaimana Metode GASING memulihkan semangat belajar anak-anak pasca-bencana. Belajar matematika yang gampang, asyik, dan menyenangkan mengembalikan keceriaan dan tawa di ruang kelas kami. Kemampuan berhitung cepat mereka kini menjadi kebanggaan orang tua dan masyarakat daerah.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Tsalitsa El May S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Sumedang yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Tsalitsa El May S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Tsalitsa El May S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Sumedang', 'Jawa Barat', 150000000.0, 0.0, 0, '1234', 'GASING DAN KEBAHAGIAAN TRAINER WIDIA BARKATI MAULIDA ASAL SDN SINDANGRASA, KOTA TASIKMALAYA, JAWA BARAT Sebiru langit dan sesegar udara dipagi hari, sinar mentari dan pepohonan yang dengan riang nya ikut menari lagu Gasing Hore. Seperti itu lah Prof, pemandangan dan aroma yang selalu saya ingat ketika pengimbasan di daerah-daerah. Selalu dengan penuh syukur dan suka cita setiap harinya. Rasanya semua hal bersama GASING sangat sulit diungkapkan dengan kata-kata, atau mungkin saya yang kurang pandai berkata-kata. G A S I N G D I H A T I K U/ 1 1 9');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Vida Viola Selfiarosa Sobuber S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Fisika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Nabire yang sedang menempuh program studi S2 Pendidikan Fisika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Vida Viola Selfiarosa Sobuber S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Vida Viola Selfiarosa Sobuber S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Nabire', 'Papua Tengah', 150000000.0, 0.0, 0, '1234', 'Mengabdi di Sorong Papua Barat Daya menyadarkan saya bahwa ketulusan pendidik adalah kunci utama keberhasilan belajar anak-anak adat. Melalui visualisasi konkret Metode GASING, anak-anak memahami konsep pecahan dan pembagian secara intuitif dan menyenangkan. GASING membuktikan bahwa setiap anak pelosok berhak dan mampu menjadi anak yang cerdas numerasi.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Wa Ariana S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Buton yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Wa Ariana S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Wa Ariana S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Buton', 'Sulawesi Tenggara', 150000000.0, 0.0, 0, '1234', 'GASING GAVE ME A CHANCE TO AND THE CHANCE TO OTHERS TRAINER WITNNY STESIA WAROUW ASAL SDN INPRES 3/77 DANOWUDU KOTA BITUNG, SULUT G A S I N G D I H A T I K U/ 1 7 9 change change');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Yenni Natalina Buknoni S.Pd.', '/assets/images/trainers/trainer_76.jpg', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Kupang yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Yenni Natalina Buknoni S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Yenni Natalina Buknoni S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Kupang', 'Nusa Tenggara Timur', 150000000.0, 0.0, 0, '1234', '"To teach is to touch a life forever" Kalau biasanya orang berkata dari mata turun ke hati, kalau kata saya, dari GASING turun ke hati. Mengapa? Karena saya tidak pernah menduga dan bahkan berpikir bahwa Metode GASING akan membuat saya begitu jatuh hati dengan matematika. Ketika pertama kali mendapatkan Metode GASING, pola pikir saya seperti diobarak-abrik. Duduk diam dan mendengarkan apa yang dijelaskan guru adalah hal yang menurut saya itu yang seharusnya ketika belajar matematika. Ternyata saya salah. Ketika potret kelas seperti itu maka kebosananlah yang akan muncul. Sangat berbeda dengan ketika belajar matematika dengan Metode GASING. Kelas begitu menyenangkan karena saya tidak hanya duduk diam dan mendengar kemudian mengangguk ketika mengerti. Tetapi saya belajar melalui cara yang sesuai dengan namanya gampang, asyik, dan menyenangkan. Saya merasa bebas berekspresi ketika belajar sambil bermain, menyanyi, bergerak mengikuti irama musik, dan berkolaborasi dengan rekan-rekan guru lainnya. Saat itu cara berpikir lama saya yang sudah tertanam selama sekian tahun bahwa mengerjakan soal-soal matematika dasar untuk penjumlahan, perkalian, pengurangan, dan pembagian harus selalu dikerjakan dari belakang pun dirombak. Bagaimana mungkin bisa soal-soal dikerjakan dari depan, apalagi untuk materi pengurangan? Itulah yang ada di benak saya. Ternyata dengan GASING bisa. Malah lebih mudah dan gampang dikerjakan. Itulah awal mulanya saya jatuh hati dengan matematika. Dan ketika saya sudah jatuh hati dengan matematika, saya pun ingin membuat orang lain ikut jatuh hati dengan matematika. Di dalam hati saya, saya ingin berbagi dengan anak-anak didik saya di kelas sehingga saya tidak lagi mendengar keluhan bahwa matematika itu sulit dan membosankan. Dan benar, dari GASING');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Yoani Mbipi S.Pd.', '/assets/images/trainers/trainer_77.jpg', 'S2 Pendidikan Matematika', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Kupang yang sedang menempuh program studi S2 Pendidikan Matematika Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Yoani Mbipi S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Yoani Mbipi S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Kupang', 'Nusa Tenggara Timur', 150000000.0, 0.0, 0, '1234', 'Perjalanan saya sebagai guru telah membawa saya ke titik yang penuh harapan dan inspirasi. Titik ini mempertemukan saya dengan Prof. Yohanes Surya saat mengikuti pelatihan GASING pertama kali di Kota Kupang. Prof. Yohanes mengatakan, "Tidak ada anak yang bodoh, hanya ada anak yang belum menemukan guru yang baik dengan metode yang tepat." Kalimat ini langsung membuat saya kagum dan berpikir bahwa ini benar adanya, sesuai dengan apa yang saya rasakan. Saya merasa belum mampu menjadi guru yang tepat karena pembelajaran matematika selalu berpusat pada saya. Saya sering menuntut siswa untuk mengikuti kemauan saya. Meskipun Kurikulum Merdeka menuntut pembelajaran yang berdiferensiasi atau berpusat pada siswa, pelaksanaan saya di dalam kelas tidak tepat. Proses pembelajaran yang monoton kadang membuat saya jenuh dan bosan. Sering kali, siswa merasa ngantuk saat belajar, yang menunjukkan bahwa saya belum mampu menciptakan kelas yang asyik dan menyenangkan. Saya sangat bersyukur karena dapat mengikuti pelatihan GASING yang diselenggarakan oleh Dinas Pendidikan Kota Kupang. Pelatihan yang berlangsung hanya 14 hari ini ternyata mampu mengubah pola pikir saya. Saya menemukan jawaban atas semua pertanyaan dan kesulitan yang saya alami selama ini. GASING bukan hanya mengajarkan cara berhitung cepat, tetapi juga mengubah saya. GASING mengajarkan saya untuk menciptakan kelas yang asyik dan menyenangkan agar anak-anak merasa nyaman. Metode ini mendorong saya untuk berkreasi dan mengajarkan saya untuk tidak berkata kasar kepada anak-anak serta menghindari kalimat negatif yang dapat menyakiti hati mereka. GASING mengajarkan saya untuk bersabar, karena ia menuntut guru untuk mengajar dengan hati dan memberi perhatian kepada anak. Ketika guru mengajar dengan hati, anak-anak akan merasakannya. Saat ini, saya telah bergabung dengan Prof. Yohanes Surya dalam visi mulia "Semua anak Indonesia pandai berhitung." Saya menyadari bahwa setiap anak memiliki potensi yang luar biasa;');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Yogina Pratiwi S.Pd.', '/assets/images/trainers/trainer_78.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Kolaka Utara yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Yogina Pratiwi S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Yogina Pratiwi S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Kolaka Utara', 'Sulawesi Tenggara', 150000000.0, 0.0, 0, '1234', 'Tiada kata yang bisa menggambarkan betapa hebatnya GASING ini. Saat pertama kali mengenalnya, saya merasa begitu asing dan bertanya-tanya, "Apakah ini sebuah metode belajar yang baru? Apakah dapat membantu siswa yang kesulitan dalam berhitung?" Hari demi hari saya jalani bersama siswa dalam pelatihan dengan rasa antusias yang besar, dan akhirnya pertanyaan saya terjawab. GASING merupakan solusi dari kesulitan siswa dalam berhitung. Sebagai seorang pendidik, saya merasa bersyukur telah mengenal GASING. Siswa yang awalnya tidak menyukai matematika kini menjawab bahwa mereka sangat menyukai mata pelajaran ini, semua itu berkat GASING. Dengan semangat yang membara, mereka bahkan berkata kepada saya, "Bu guru, saya mempunyai mimpi besar ingin menjadi profesor seperti Profesor Yohanes Surya dan ingin menjadi guru seperti Ibu Yogina." Setelah mendengar itu, saya tersenyum dan merasa bangga bahwa mereka memiliki mimpi besar, yang diharapkan dapat memberikan kontribusi bagi Indonesia di masa depan. GASING memberikan perubahan yang begitu besar dalam diri saya. Saya merupakan seorang pendidik yang kaku dan cukup keras dalam kegiatan belajar. Namun, bertemu dengan GASING membuat karakter saya berubah; saya menjadi lebih banyak tersenyum, selalu bersemangat dalam kegiatan belajar, dan mengubah tingkah laku saya yang sudah di luar prediksi BMKG (hahahah). Saya pernah bermimpi untuk berkeliling di seluruh daerah di Indonesia, menyalurkan ilmu dan membuat Indonesia lebih unggul di kancah internasional. Melalui GASING, saya, yang berasal dari desa, bisa menginjakkan kaki dan diberikan kesempatan untuk mengajar GASING kepada anak-anak yang memiliki karakter dan ciri khasnya sendiri. Pengimbasan pertama saya di Papua terasa luar biasa; melihat antusiasme anak-anak sangat menyala. Pengimbasan kedua saya di Bali juga memberikan banyak pelajaran, baik dari kebudayaan maupun semangat siswa dalam belajar.');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Yohana Barita Napitupuluh S.Pd.Gr.', '/assets/images/trainers/default.png', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Kepulauan Mentawai yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Yohana Barita Napitupuluh S.Pd.Gr. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Yohana Barita Napitupuluh S.Pd.Gr. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Kepulauan Mentawai', 'Sumatera Barat', 150000000.0, 0.0, 0, '1234', 'Hal pertama yang ingin saya sampaikan kepada Prof. Yohanes Surya dan tim hebatnya adalah luar biasa dan terima kasih. Saya sangat bersyukur dan bangga bisa bergabung dengan orang-orang hebat, hangat, supel, dan luar biasa di Gasing Academy. GASING tidak hanya memberikan metode dan ilmu pengetahuan saat pengimbasan, tetapi juga membawa harapan baru bagi semua peserta. Hal ini terbukti saat pengimbasan pertama saya di Lanny Jaya, Papua Pegunungan, di mana saya dipercaya membimbing siswa SMP. Dalam pikiran saya, mengajar anak-anak SMP pasti tidak sulit. Namun, saya terharu saat menemukan salah satu murid saya di kelas VIII yang belum lancar membaca dan menulis, serta mengalami kesulitan dalam berbahasa Indonesia. Hal ini membuatnya merasa malu dan tidak percaya diri. Meskipun sempat pesimis, semangat dan kegigihannya untuk berjalan kaki selama 1-2 jam setiap hari demi mengikuti kegiatan GASING memotivasi saya. Yohana Barita Napitupulu,S.Pd.Gr - Trainer Kepulauan Mentawai GASING Membawa Harapan');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Yohana Christina Rahangmetan S.Pd.', '/assets/images/trainers/trainer_80.jpg', 'S2 Pendidikan Guru Sekolah Dasar', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Mappi yang sedang menempuh program studi S2 Pendidikan Guru Sekolah Dasar Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Yohana Christina Rahangmetan S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Yohana Christina Rahangmetan S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Mappi', 'Papua Selatan', 150000000.0, 0.0, 0, '1234', 'Bulan Maret Tahun 2023, saya mendapatkan kesempatan untuk menjadi peserta pelatihan GASING yang diselenggarakan kabupaten saya yaitu Kabupaten Mappi. Dihari pertama mengikuti kegiatan, jujur saya merasa bosan, dikarenakan materi yang diterima dan kami imbaskan pada peserta didik adalah pengenalan bilangan 1 - 5, yang menurut saya sangat mudah. Tetapi dalam kegiatan dihari berikutnya, saya mulai tertarik dan merasa sangat antusias mengikuti kegiatan.. Setelah 14 hari saya mengikuti kegiatan, saya merasa menjadi lebih pandai. Saya memang menyukai matematika, tetapi jujur saya akui, GASING benar-benar luar biasa. Saya bisa mencongak perkalian 2 angka, bahkan bisa mencongak pembagian banyak angka dengan 1 angka. Setelah kegiatan, saya mendapatkan penawaran untuk mengikuti pengimbasan Nasional Bersama GASING di kabupaten Ende. Untuk pertama kalinya saya melakukan perjalanan yang jauh. Mulai dari Mappi hingga sampai di Ende. Perjalanan yang melelahkan, tetapi terbayar sempurna dengan pemandangan ende yang luar biasa indah. Untuk pertama kali, saya mengajar siswa dari sekolah lain. Tetapi saya sangat bersyukur, seluruh siswa yang saya ajarkan di kelas A waktu itu, dapat menerima GASING dengan baik dan kemampuan berhitung mereka menjadi meningkat dan lebih baik. Setelah kegiatan pengimbasan Nasional di Ende, saya mendapatkan kesempatan luar biasa, mengantar anak-anak asli Mappi yang telah dilatih GASING untuk melakukan interaksi Bersama Presiden RI Joko Widodo di Jayapura. Sungguh pengalaman yang luar biasa, saya bisa bertemu dan melihat langsung bapak Jokowi, bahkan saya bisa berfoto Bersama bapak Jokowi. Pengalaman luar biasa yang tidak pernah saya bayangkan, bahkan bermimpipun tidak pernah. Beberapa bulan berlalu, saya mendapatkan kesempatan lagi untuk mengimbas secara nasional ke kabupaten Sorong. Ini juga');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Yudi Braja Putra. S.Pd.', '/assets/images/trainers/default.png', 'S2 Pendidikan Dasar Kampus Bandung', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Siak yang sedang menempuh program studi S2 Pendidikan Dasar Kampus Bandung Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Yudi Braja Putra. S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Yudi Braja Putra. S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Siak', 'Riau', 150000000.0, 0.0, 0, '1234', 'Ada sebuah istilah, "mengajar belasan tahun pengalaman hanya satu tahun." Istilah ini tepat menggambarkan bagaimana seorang pengajar atau pendidik yang dari tahun ke tahun tidak mengalami perubahan dalam strategi mengajarnya; monoton, itu ke itu saja. Setelah belasan tahun mengajar, khususnya di bidang studi matematika, saya belum menemukan strategi yang membuat anak mampu memahami konsep matematika. Walau ada banyak strategi, model, dan metode yang telah diterapkan, hasil yang didapat tidak sesuai dengan yang diinginkan. Mengajar matematika sangatlah sulit; saya menjadi pribadi yang pemarah, tidak sabaran, dan sering menyalahkan siswa atas ketidakmampuan saya. Pertengahan tahun 2023, di akhir tahun pelajaran menjelang liburan, saya dipilih menjadi peserta pelatihan oleh atasan saya. Setelah berjalan 4 hari pelatihan, trainer memperlihatkan video pengimbasan di daerah-daerah lain. Batin saya menjerit dan menangis dalam hati. Trainer-trainer yang ditampilkan mengajar dengan dedikasi tinggi, totalitas, semangat, dan penuh cinta. Ini yang hilang dari saya selama ini. Seiring waktu, saat mengimbas ke berbagai daerah, saya menemukan metode yang selama ini saya dan siswa cari: Metode GASING, yang sangat Gampang, Asyik, dan Menyenangkan. Sedikit demi sedikit, saya masuk ke dunia anak. Kami bernyanyi, menari, berjoget, dan berlomba dalam proses belajar. Dari pagi hingga sore selama belasan hari, tanpa rasa bosan, yang ada hanya kebahagiaan dan banyak perubahan pada diri saya. Awalnya, ketidakhadiran saya di kelas dirayakan dengan bahagia oleh siswa karena mereka tidak belajar. Sekarang, ketidakhadiran saya diiringi dengan air mata—air mata rindu. Rindu ingin belajar bersama. Cinta itu telah dipertemukan oleh Metode GASING. Terima kasih, Prof. Yohanes Surya. Yudi Braja Putra, S.Pd. - Trainer Kabupaten Siak GASING Mengubahku Menjadi Pendidik Sejati');
INSERT INTO trainers (name, photo_url, major, university, bio, story_emotional, home_regency, home_province, target_funding, current_funding, is_funded, password, gasing_testimony) VALUES ('Zet Latuminase S.Pd.', '/assets/images/trainers/trainer_82.jpg', 'S2 Psikologi Pendidikan', 'Universitas Pendidikan Indonesia (UPI)', 'Seorang trainer GASING berdedikasi tinggi asal Ambon yang sedang menempuh program studi S2 Psikologi Pendidikan Magister by Research di Universitas Pendidikan Indonesia.', 'Sebelumnya, Zet Latuminase S.Pd. dijanjikan program beasiswa LPDP untuk membiayai kelanjutan studi S2 di UPI. Namun, karena kendala administratif birokrasi, dana beasiswa tersebut belum terealisasikan hingga semester ini. Sebagai trainer yang berkomitmen tinggi memajukan numerasi anak-anak daerah asal, Zet Latuminase S.Pd. membutuhkan dukungan beasiswa alternatif sebesar Rp 150.000.000 untuk dapat melunasi biaya SPP dan menuntaskan riset tugas akhir demi kembali mengabdi di pelosok daerah.', 'Ambon', 'Maluku', 150000000.0, 0.0, 0, '1234', 'Akhirnya saya menemukan siapa sebenarnya saya di GASING. Hai, sahabat GASING, saya adalah guru pada SD Negeri 16 Ambon yang sudah mengajar selama 15 tahun. Namun profesi sebagai guru sebenarnya bukan cita-cita saya, karena sesungguhnya saya adalah orang yang introvert. Minder, kurang percaya diri, gugup di depan banyak orang bahkan di depan para peserta didik di kelas, itulah saya sebelumnya. Selama menjadi guru, sekolah sangat membosankan karena saya tidak mampu berkata-kata di depan peserta didik untuk mengajar. Saya sangat membenci situasi dimana saat saya akan mengajar dan ada teman sejawat yang duduk di kelas. Saya akan gugup, berkeringat dan tidak mampu berkata-kata. Apalagi berbicara tentang matematika, pelajaran yang sangat saya takuti bahkan malas mendengarnya sejak SD. Hingga setelah menjadi guru pun saat di kelas saya selalu menghindar untuk mengajar matematika kepada peserta didik. Biasanya ada teman sejawat yang diminta untuk mengajarkan matematika di kelas saya. Hingga pada bulan Maret 2023 sebuah anugerah terjadi dalam hidup saya bahkan karir saya sebagai guru. Saya dipilih menjadi peserta Pelatihan Ambon Pandai Berhitung dengan Metode GASING. Sejak saat itu metode yang ditemukan oleh Prof. Yohanes Surya, Ph.D ini telah mengubah pribadi saya bahkan karir saya sebagai guru. Dalam GASING saya menemukan versi saya yang sebenarnya, saya telah menemukan tujuan saya menjadi guru. Karena GASING seorang guru yang awalnya minder, gugup, kurang percaya diri, saat ini bisa dengan sangat nyaman berdiri, berlari, melompat menyanyi dan menari di depan banyak orang saat mengajar. Karena GASING seorang guru yang takut matematika sejak kecil, sekarang sangat mencintai matematika dan terus antusias untuk belajar bahkan mengajar. GASING tidak hanya menciptakan guru yang pandai berhitung, tetapi juga guru yang berkarakter, percaya diri, kreatif, disiplin dan mengajar dengan hati. GASING sangat tepat untuk menjadi sarana perubahan wajah pendidikan Indonesia menuju "Indonesia Emas 2045"');